import type { Drill } from "./types";

// Doctor / mid drills, keyed by module slug — 25 per module.
// Attending physician leading a service or clinic: rounds, family conferences,
// QI committees, resident feedback, nursing coordination. Merged into course.ts.
export const DOCTOR_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-doc-mid-01","level":"mid","profession":"doctor","title":"The rounds presentation that buries the plan","scenario":"You're leading morning rounds on a 22-bed service. For the sickest patient, the resident's presentation is running long and the team is drifting. You take over to model how it's done: the plan for today should come first, not after five minutes of history.","task":"Write a 2-3 sentence rounds summary that opens with today's plan for the patient.","tips":["Sentence one: what changes for this patient today.","History and overnight events are support, not the headline.","Model the structure you want residents to copy."],"focus":["structure","concision"],"placeholder":"Plan for bed 12 today: advance diet, stop IV fluids, target discharge Thursday —"},
    {"id":"lead-doc-mid-02","level":"mid","profession":"doctor","title":"The consult request with no question","scenario":"You're paging cardiology about a patient on your service. Your draft message recounts the whole admission before getting to what you actually need: their opinion on whether the patient is safe for surgery next week.","task":"Rewrite the consult request so the specific question comes in sentence one.","tips":["Lead with the question you need answered and by when.","One line of essential context, then stop.","A clear question gets a same-day consult; a story gets triaged to tomorrow."],"focus":["clarity","concision"],"placeholder":"Consult question: is this patient safe to clear for surgery next Tuesday?"},
    {"id":"lead-doc-mid-03","level":"mid","profession":"doctor","title":"The staffing email that eases in","scenario":"You're emailing the department chief to ask for a fourth physician on the inpatient service. Your draft spends two paragraphs on census trends before the ask appears. The chief reads email between meetings and rarely gets past line three.","task":"Write a 3-4 sentence email that puts the ask in the first sentence.","tips":["Open with the request: one additional physician, starting when.","Follow with the two strongest supporting numbers.","End with the decision you need and a date."],"focus":["structure","impact"],"placeholder":"I'm requesting a fourth attending for the inpatient service starting July —"},
    {"id":"lead-doc-mid-04","level":"mid","profession":"doctor","title":"The family callback","scenario":"A patient's daughter left three messages asking when her father can go home. You're returning the call between clinic patients. The answer is Friday, if his walking improves. Your instinct is to walk her through the whole care plan first.","task":"Write the first two sentences of the call, leading with the answer to her question.","tips":["She asked one question — answer it in your first breath.","The condition attached to the date comes second, briefly.","Details of the care plan are available if she asks."],"focus":["clarity","audience"]},
    {"id":"lead-doc-mid-05","level":"mid","profession":"doctor","title":"The incident summary for the safety committee","scenario":"You're submitting a summary of a wrong-dose near-miss to the patient safety committee. Your draft opens with background on the unit's workload before stating what actually happened and what you've changed.","task":"Write a 2-3 sentence summary that states the event and the fix up front.","tips":["Sentence one: what nearly happened and the harm it could have caused.","Sentence two: what has already been changed.","Context about workload belongs in the discussion section, not the opening."],"focus":["structure","precision"],"placeholder":"On March 4 a tenfold dosing error was caught at the bedside before administration —"},
    {"id":"lead-doc-mid-06","level":"mid","profession":"doctor","title":"The evening handoff","scenario":"You're handing the service to the night attending. One patient is genuinely worrying — new confusion this afternoon, pending scan. Your handoff draft walks bed by bed in room order, reaching the sick patient twelfth.","task":"Write a handoff opening that leads with the one patient the night doctor must watch.","tips":["First line: the sickest patient, what's pending, and the trigger to act.","Stable patients can be a list at the end.","If the night attending remembers one thing, choose it for them."],"focus":["structure","impact"],"placeholder":"Watch bed 8 first: new confusion since 3pm, head CT pending —"},
    {"id":"lead-doc-mid-07","level":"mid","profession":"doctor","title":"The QI proposal that hides the change","scenario":"You're proposing that the unit adopt a discharge checklist to the quality committee. Your one-page memo spends the first half describing the readmission problem. The actual proposal — a five-item checklist at every discharge — appears in paragraph four.","task":"Rewrite the memo's opening so the proposed change is stated in sentence one.","tips":["Lead with the proposal, not the problem history.","One sentence of evidence that it will work.","Name the approval you need from this committee."],"focus":["structure","clarity"]},
    {"id":"lead-doc-mid-08","level":"mid","profession":"doctor","title":"The near-miss message to the nurse manager","scenario":"Two look-alike medication vials were stocked side by side and a nurse nearly grabbed the wrong one. You've agreed on the fix — separate the bins today. Your message to the nurse manager starts with reassurance and praise before the action.","task":"Write a message that leads with the action needed today.","tips":["Open with the fix and the deadline: separate the bins before the evening shift.","The near-miss story is one supporting sentence.","Appreciation can close the message; it shouldn't open it."],"focus":["clarity","impact"],"placeholder":"Please have the two vials moved to separate bins before evening shift —"},
    {"id":"lead-doc-mid-09","level":"mid","profession":"doctor","title":"The capacity question from the CMO","scenario":"The chief medical officer messages you directly: can your service absorb four more admissions from the ED tonight? The honest answer is yes, but only with an extra nurse. Your draft reply explains the census math before answering.","task":"Write a reply that answers the question in the first three words, then states the condition.","tips":["Lead with yes or no — the CMO is making a decision right now.","Attach the condition in the same breath: yes, if we get one more nurse.","Numbers support the condition; they don't replace the answer."],"focus":["clarity","concision"],"placeholder":"Yes — if we get one additional nurse for the night shift."},
    {"id":"lead-doc-mid-10","level":"mid","profession":"doctor","title":"The discharge summary opener","scenario":"You're dictating a discharge summary that the patient's family doctor will skim in ninety seconds. Your usual habit is to open with the admission story. What the family doctor needs first: final diagnosis, what changed, and what they must follow up.","task":"Write the first two sentences of the summary, leading with the outcome and the follow-up.","tips":["Sentence one: final diagnosis and how the patient left.","Sentence two: the one thing the family doctor must do.","The admission narrative can follow for those who read on."],"focus":["structure","audience"]},
    {"id":"lead-doc-mid-11","level":"mid","profession":"doctor","title":"The postponement call to the surgeon","scenario":"You're recommending that tomorrow's elective procedure be postponed because the patient spiked a fever tonight. The surgeon is between cases and will give you thirty seconds. Your instinct is to open with an apology and the backstory.","task":"Write the first two sentences of the call, recommendation first.","tips":["Lead with the recommendation: postpone, and why in five words.","Offer the next step — a new date or a recheck plan.","Skip the apology; this is the system working."],"focus":["clarity","impact"],"placeholder":"I recommend we postpone tomorrow's case — she spiked a fever tonight."},
    {"id":"lead-doc-mid-12","level":"mid","profession":"doctor","title":"The M&M opening line","scenario":"You're presenting a case at morbidity and mortality conference. The teaching point is that a critical lab result sat unseen in the inbox for six hours. Tradition says you walk through the case chronologically; the room learns more if you name the lesson first.","task":"Write an opening line that states the teaching point before the case begins.","tips":["Lead with the system lesson, not the patient's history.","One sentence framing what the audience should watch for.","The chronology then becomes evidence for the point."],"focus":["structure","impact"],"placeholder":"This case is about a critical result that nobody saw for six hours —"},
    {"id":"lead-doc-mid-13","level":"mid","profession":"doctor","title":"The protocol announcement","scenario":"Your unit adopts a new sepsis screening protocol on Monday. Your announcement draft to the team opens with the committee history and the evidence review. What the team needs first: what they do differently starting Monday.","task":"Write a 2-3 sentence announcement that leads with what changes on Monday.","tips":["Sentence one: the new behavior and the start date.","Sentence two: the one-line reason.","Link to the full protocol instead of summarizing it."],"focus":["clarity","concision"],"placeholder":"Starting Monday, every admission gets the new sepsis screen at triage —"},
    {"id":"lead-doc-mid-14","level":"mid","profession":"doctor","title":"The family meeting opener","scenario":"You're opening a scheduled family meeting about a patient whose recovery has stalled. The family has been waiting all day and is braced for a runaround. You have a clear message: he is stable, but he will need rehab, not home, when he leaves.","task":"Write the first two sentences of the meeting, headline first.","tips":["State the main message in the first sentence — stable, but rehab next.","Then pause and invite questions; don't stack ten details.","Warmth and directness are not opposites."],"focus":["clarity","audience"]},
    {"id":"lead-doc-mid-15","level":"mid","profession":"doctor","title":"The project update to the committee","scenario":"Your catheter-infection project has a result worth leading with: infections are down from six per quarter to two. Your update draft opens with a recap of the methodology, and the number appears on slide five.","task":"Write a 1-2 sentence update that puts the result first.","tips":["Lead with the outcome number and the comparison.","Method questions will come — answer them when asked.","Give the committee its headline in the first breath."],"focus":["impact","precision"],"placeholder":"Catheter infections are down from six per quarter to two —"},
    {"id":"lead-doc-mid-16","level":"mid","profession":"doctor","title":"The drug-shortage decision","scenario":"Pharmacy tells you a common medication on your unit is on national backorder. You've decided on the standard substitute. Your message to the team drafts long: the shortage news, the supply chain story, then the decision.","task":"Write a message that leads with the decision, not the shortage story.","tips":["Sentence one: use drug B in place of drug A, effective now.","One line on why, one line on where to ask questions.","The supply chain saga is background nobody needs to act."],"focus":["clarity","structure"],"placeholder":"Effective today, use the standard substitute for all new orders —"},
    {"id":"lead-doc-mid-17","level":"mid","profession":"doctor","title":"The resident's discharge question","scenario":"Your senior resident messages you: can bed 14 go home today? You've reviewed the chart and the answer is yes. Your draft reply starts with everything you checked before giving the verdict, which teaches thoroughness but wastes their afternoon.","task":"Write a reply that gives the verdict first, then one teaching point.","tips":["Answer in word one: yes.","Add the single most useful reason so they learn your reasoning.","Save the full checklist for teaching rounds."],"focus":["concision","clarity"],"placeholder":"Yes — discharge today. The deciding factor for me was..."},
    {"id":"lead-doc-mid-18","level":"mid","profession":"doctor","title":"The coverage swap request","scenario":"You need a colleague to cover your Saturday call so you can attend a family event. Your draft message spends four sentences on how much you hate asking before the request appears.","task":"Write a 2-sentence request that leads with the specific ask and the trade you're offering.","tips":["Sentence one: the date, the shift, and what you'll cover in return.","Make yes easy: name the exchange, don't leave it open.","Cut the apologetic wind-up entirely."],"focus":["clarity","concision"],"placeholder":"Could you take my Saturday call on the 14th? I'll cover your next weekend —"},
    {"id":"lead-doc-mid-19","level":"mid","profession":"doctor","title":"The bed huddle report","scenario":"At the 9am hospital bed huddle, every service gets thirty seconds. The bed manager needs one number from you: how many discharges by noon. Your habit is to describe the barriers first.","task":"Write your 30-second huddle report, leading with the discharge number.","tips":["First words: the number of discharges and by when.","Then the single barrier someone in the room can fix.","Everything else is noise at this meeting."],"focus":["concision","impact"],"placeholder":"Three discharges by noon. One barrier: bed 6 is waiting on transport —"},
    {"id":"lead-doc-mid-20","level":"mid","profession":"doctor","title":"The referral letter","scenario":"You're referring a clinic patient to a specialist with a six-month waitlist. Referrals that state the question clearly get triaged faster. Your dictation habit opens with demographics and the full medication list.","task":"Write the first two sentences of the referral, leading with the question and the urgency.","tips":["Sentence one: what you're asking the specialist to assess and how soon.","Sentence two: the single finding that justifies the urgency.","The medication list attaches; it doesn't lead."],"focus":["clarity","precision"]},
    {"id":"lead-doc-mid-21","level":"mid","profession":"doctor","title":"The order-set bug report","scenario":"You've found that a default dose in an electronic order set is wrong — not dangerous yet, but it will be. Your email to the informatics team drafts polite and slow, with the actual error in paragraph two.","task":"Write an email opening that names the error and the risk in sentence one.","tips":["Lead with what's wrong, where, and what could happen.","Ask for a correction date in sentence two.","Politeness survives bluntness; patients may not survive delay."],"focus":["impact","precision"],"placeholder":"The admission order set defaults to double the intended dose —"},
    {"id":"lead-doc-mid-22","level":"mid","profession":"doctor","title":"The clinic staff meeting opener","scenario":"You run the monthly clinic staff meeting. This month there's one change that matters — same-day slots are moving to the morning — plus a dozen routine notices. Your draft agenda gives everything equal billing.","task":"Write the meeting's opening two sentences, leading with the one change that matters.","tips":["Name the headline change first and who it affects.","Batch routine notices into a handout or a closing minute.","If everything is important, nothing is."],"focus":["structure","clarity"]},
    {"id":"lead-doc-mid-23","level":"mid","profession":"doctor","title":"The reply to legal counsel","scenario":"Hospital counsel emails asking one factual question: were you the attending of record on March 3? You were. Your draft reply anxiously narrates the whole week around that date.","task":"Write a reply that answers the question in the first sentence, adding nothing unrequested.","tips":["Answer exactly what was asked, first.","Offer to provide more if needed — don't volunteer it.","Anxious over-explaining creates work for everyone."],"focus":["concision","precision"],"placeholder":"Yes, I was the attending of record on March 3."},
    {"id":"lead-doc-mid-24","level":"mid","profession":"doctor","title":"The surge plan update","scenario":"Respiratory season is spiking and department leadership asked how your service will handle it. You have a plan: open six flex beds and move one physician to admissions. Your draft memo builds suspense through three paragraphs of volume data first.","task":"Write a 2-3 sentence update that states the plan up front.","tips":["Sentence one: the two moves you're making and when.","Sentence two: what you need from leadership to execute.","Volume data is an appendix, not an overture."],"focus":["structure","impact"],"placeholder":"Our surge plan: open six flex beds Monday and shift one attending to admissions —"},
    {"id":"lead-doc-mid-25","level":"mid","profession":"doctor","title":"The peer-review conclusion","scenario":"You reviewed a colleague's case for the peer-review committee and found the care met the standard. Your written review walks through the chart chronologically, and your conclusion appears only in the final line — where a skimming committee may miss it.","task":"Rewrite the review's opening so the conclusion comes first, then the reasoning.","tips":["State your finding in sentence one: care met the standard.","Then give the two observations that support it.","A buried conclusion invites the committee to write its own."],"focus":["structure","clarity"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-doc-mid-01","level":"mid","profession":"doctor","title":"Why nothing to eat after midnight","scenario":"A patient's son is upset that his mother can't eat before tomorrow's procedure — she's hungry and he thinks the rule is bureaucratic. You know the safety reason cold, but your first instinct is to cite policy.","task":"Write a 2-3 sentence explanation in terms of what the family cares about: her safety.","tips":["Lead with her stake: this keeps her safe during sedation.","Skip the physiology lecture unless they ask.","Acknowledge the discomfort — it's real, and naming it buys trust."],"focus":["audience","clarity"],"placeholder":"I know she's hungry, and I'm sorry — this rule is about keeping her safe tomorrow."},
    {"id":"audience-doc-mid-02","level":"mid","profession":"doctor","title":"The surgery delay explanation","scenario":"A family has been waiting since 7am and the procedure keeps slipping because emergencies are jumping the queue. The scheduling reality involves OR turnover, case priority, and staffing — none of which they should need to decode.","task":"Write a 2-3 sentence explanation a stressed family can absorb, with an honest next update time.","tips":["Translate the queue into their terms: emergencies go first, and hers is safe to wait.","Give a concrete next update time — vagueness reads as evasion.","Don't over-apologize into meaninglessness; inform and commit."],"focus":["audience","clarity"]},
    {"id":"audience-doc-mid-03","level":"mid","profession":"doctor","title":"Quality metrics for the board","scenario":"You're presenting your unit's quality dashboard to the hospital board — accountants, lawyers, a retired banker. Your slides say things like \"CLABSI rate per 1,000 line-days.\" They govern money and risk, not medicine.","task":"Rewrite one metric line so a non-clinical board member understands what it measures and why it matters.","tips":["Translate the metric into patients and consequences, not acronyms.","Anchor to what boards manage: risk, cost, reputation.","One metric explained well beats five recited."],"focus":["audience","precision"],"placeholder":"This line tracks serious infections from IV lines — we've cut them from six a year to two."},
    {"id":"audience-doc-mid-04","level":"mid","profession":"doctor","title":"Length of stay, explained to finance","scenario":"The finance director asks why your service's average length of stay rose half a day this quarter. The honest answer involves sicker patients and a rehab-bed shortage downstream. Your draft is written for doctors, full of clinical shorthand.","task":"Write a 3-4 sentence explanation in operational and financial terms.","tips":["Lead with the two drivers in plain words.","Quantify what finance can act on: the rehab-bed bottleneck.","Skip clinical detail that doesn't change their decision."],"focus":["audience","clarity"]},
    {"id":"audience-doc-mid-05","level":"mid","profession":"doctor","title":"What the ward clerk should escalate","scenario":"A new ward clerk is fielding calls from families and doesn't know which ones need a doctor now versus a message. Your first draft of guidance lists diagnoses. She needs behaviors and phrases she'll actually hear on the phone.","task":"Write 2-3 sentences of guidance in terms of what she will hear, not what it means clinically.","tips":["Give her ear-level cues: words callers use, not diagnoses.","One clear rule beats a taxonomy: when unsure, interrupt me.","Make the escalation path one step, not a flowchart."],"focus":["audience","clarity"],"placeholder":"If a caller says anything like \"much worse,\" \"can't breathe,\" or \"not making sense,\" interrupt me —"},
    {"id":"audience-doc-mid-06","level":"mid","profession":"doctor","title":"The plain-words diagnosis","scenario":"You're explaining a new chronic diagnosis to a patient who told you she left school at fourteen and finds hospitals overwhelming. Your usual explanation uses four terms she'd have to look up.","task":"Write a 3-sentence explanation using no word you'd have to define.","tips":["Say what it means for her days, not what it's called.","One idea per sentence; check understanding before adding more.","Plain language is precision for this audience, not dumbing down."],"focus":["audience","clarity"]},
    {"id":"audience-doc-mid-07","level":"mid","profession":"doctor","title":"Selling the protocol to nursing","scenario":"You're introducing a new assessment protocol at the nursing huddle. Your draft explains why physicians like the evidence. Nurses will ask a different question: what does this add to a twelve-hour shift that's already full?","task":"Write a 2-3 sentence pitch framed around the nursing workflow, not the evidence review.","tips":["Lead with their stake: fewer emergency escalations mid-shift.","Be honest about the added minutes — they'll count them anyway.","Evidence citations convince committees; workload math convinces shifts."],"focus":["audience","impact"],"placeholder":"This adds about ninety seconds per assessment, and here's what it buys you on nights —"},
    {"id":"audience-doc-mid-08","level":"mid","profession":"doctor","title":"Rounds expectations for the new student","scenario":"A third-year medical student joins your service tomorrow — their first clinical rotation ever. Your usual orientation email assumes they know what \"pre-rounding\" and \"running the list\" mean. They don't.","task":"Write a 3-4 sentence orientation note that assumes zero hospital experience.","tips":["Spell out the shorthand: what happens, when, and what they do.","Name the one thing that matters most on day one.","Remember what you didn't know then — that's the curse of knowledge."],"focus":["audience","structure"]},
    {"id":"audience-doc-mid-09","level":"mid","profession":"doctor","title":"The portal message reply","scenario":"A patient messaged through the portal asking if her test results are \"bad.\" The results are mildly abnormal and need a repeat in three months — routine to you, alarming words to her. Your draft reply reads like a chart note.","task":"Write a 2-3 sentence portal reply in words that inform without alarming.","tips":["Answer her actual question first: is this bad? Mostly no, and here's the plan.","Replace chart language with everyday words.","Say exactly what happens next and who arranges it."],"focus":["audience","clarity"],"placeholder":"Your results are mildly off in one area — not dangerous, but worth rechecking in three months."},
    {"id":"audience-doc-mid-10","level":"mid","profession":"doctor","title":"Why the monitor is coming off","scenario":"You're discontinuing continuous heart monitoring for a patient because he no longer needs it. His wife sees the monitor as the thing keeping him safe, and she's alarmed. The clinical logic — he's stable, the monitor now adds noise, not safety — needs her framing, not yours.","task":"Write a 2-3 sentence explanation that addresses what the monitor means to her.","tips":["Start from her fear: taking it away feels like removing protection.","Reframe: this is a promotion — he's well enough not to need it.","Say what safety net remains."],"focus":["audience","clarity"]},
    {"id":"audience-doc-mid-11","level":"mid","profession":"doctor","title":"Briefing communications on the outbreak","scenario":"There's a small contained infection cluster on one ward, and the hospital communications team needs to prepare a public statement. Your first draft briefing is written like an infection-control report. They need what they can say, in words the public will read.","task":"Write a 3-sentence brief for the communications team: what happened, what's being done, what's safe to say.","tips":["Separate facts they can publish from details they can't.","Give them plain sentences they can quote directly.","Flag the one question reporters will ask and its answer."],"focus":["audience","precision"]},
    {"id":"audience-doc-mid-12","level":"mid","profession":"doctor","title":"The consent conversation","scenario":"You're consenting a patient for a routine procedure. The form is two pages of legal prose; your job is the conversation. He's nodding along too quickly, which usually means he's understood nothing and is embarrassed to say so.","task":"Write 2-3 sentences explaining the main risk and benefit in words that invite questions.","tips":["One benefit, one main risk, in kitchen-table words.","End with a question that checks understanding without quizzing him.","Nodding is not consent; comprehension is."],"focus":["audience","clarity"],"placeholder":"The procedure fixes X in about 40 minutes; the main risk we watch for is bleeding. What questions do you have so far?"},
    {"id":"audience-doc-mid-13","level":"mid","profession":"doctor","title":"One pitch, one audience","scenario":"You're rolling out the sepsis protocol to the emergency department next month. You drafted one email for \"all clinical staff,\" and it lands with nobody: ED physicians care about door-to-decision speed, ward nurses about handoff clarity. You can only send one message today.","task":"Pick ONE primary audience and rewrite the 2-3 sentence pitch for them alone.","tips":["Choose the audience whose behavior must change first.","Write to their pressure, not to a committee-approved average.","The other audiences get their own message later — that's a feature."],"focus":["audience","impact"]},
    {"id":"audience-doc-mid-14","level":"mid","profession":"doctor","title":"The discharge coordinator business case","scenario":"You want to hire a discharge coordinator for the unit. To you the case is about patient flow and safer transitions. The CEO who approves the position thinks in cost per bed-day and revenue. Your draft leads with care quality and loses him by line two.","task":"Write a 2-3 sentence pitch translated into the CEO's terms.","tips":["Lead with the number: bed-days freed, at what saving.","Quality outcomes support the math; they don't replace it.","Ask for a decision, not for sympathy."],"focus":["audience","impact"],"placeholder":"A discharge coordinator would free an estimated 300 bed-days a year —"},
    {"id":"audience-doc-mid-15","level":"mid","profession":"doctor","title":"Observation versus admitted","scenario":"A patient's husband is confused and angry: the hospital says his wife is here under \"observation status,\" and he's heard that means bigger bills. The billing distinction is real, arcane, and not your creation — but you're the one standing in the room.","task":"Write a 2-3 sentence explanation of the distinction in his terms, plus who can answer the billing question exactly.","tips":["Explain the practical difference without defending the bureaucracy.","Separate what you control (her care is identical) from what you don't (billing categories).","Route him to the person with real billing answers — a name, not a department."],"focus":["audience","clarity"]},
    {"id":"audience-doc-mid-16","level":"mid","profession":"doctor","title":"The handoff for the locum","scenario":"A locum physician covers your service this weekend — competent, but new to the building. Your usual handoff note is full of local shorthand: \"the usual bed 4 situation,\" \"call the second pager,\" \"the Friday list.\" None of it decodes.","task":"Rewrite two lines of your handoff so someone with zero local knowledge can act on them.","tips":["Replace every local shorthand with the actual instruction.","Include the phone numbers and names you carry in your head.","Test: could a stranger follow this at 2am? That's the bar."],"focus":["audience","precision"],"placeholder":"For the patient in bed 4: if his drain output exceeds 200ml, call Dr. Okafor directly at —"},
    {"id":"audience-doc-mid-17","level":"mid","profession":"doctor","title":"Why room turnover timing matters","scenario":"Isolation rooms are being cleaned out of order, delaying admissions. You're writing to the environmental services supervisor. Your draft explains infection-control theory; her team needs to know which rooms first and why it matters to their work.","task":"Write a 2-3 sentence request framed around her team's workflow and the concrete priority.","tips":["Lead with the operational rule: isolation rooms before standard rooms.","Give the reason at their altitude: these rooms block sick patients from coming up.","Respect expertise — ask what would make the sequence workable."],"focus":["audience","clarity"]},
    {"id":"audience-doc-mid-18","level":"mid","profession":"doctor","title":"The community-center talk","scenario":"You're giving a twenty-minute talk on preventive health at a community seniors' center. Your slide deck was built for grand rounds. The audience wants to know two things: what should I do, and how do I know when something's wrong?","task":"Write the 2-3 sentence opening of the talk, pitched at their questions, not your literature review.","tips":["Open with what they'll be able to do by the end.","Cut every statistic that doesn't change their behavior.","Speak to the person in row three, not to the field."],"focus":["audience","impact"]},
    {"id":"audience-doc-mid-19","level":"mid","profession":"doctor","title":"Same change, two readers","scenario":"You're changing a patient's long-standing medication. Two messages result: one to the pharmacist (interaction check, timing) and one to the patient (what to take, what to notice). You drafted one message trying to serve both and it serves neither.","task":"Write the PATIENT version in 2-3 sentences — plain words, actions, and what to watch for.","tips":["The patient needs actions: stop this, start that, watch for these two things.","Move all professional detail to the pharmacist's message.","One reader per message; hybrids fail both."],"focus":["audience","clarity"],"placeholder":"Starting tomorrow, stop your current tablet and take the new one with breakfast."},
    {"id":"audience-doc-mid-20","level":"mid","profession":"doctor","title":"The work note that works","scenario":"A patient recovering from surgery needs a letter for her employer about modified duties. Your draft is clinical: procedure names, healing timelines. Her manager needs exactly two things: what she can't do, and until when.","task":"Write a 2-sentence work letter in the employer's terms.","tips":["State the restriction and the end date — that's the whole letter.","No diagnosis details; the employer neither needs nor should have them.","Precision here protects the patient's privacy and her job."],"focus":["audience","precision"]},
    {"id":"audience-doc-mid-21","level":"mid","profession":"doctor","title":"Telling IT what clinicians need","scenario":"The order-entry screen for your unit's most common admission takes eleven clicks. You're meeting the clinical informatics team. Your draft complaint says \"the system doesn't reflect clinical workflow\" — true, and useless to an analyst.","task":"Write a 2-3 sentence request in terms IT can act on: clicks, screens, and the target.","tips":["Count the clicks; name the screens. Specifics are buildable.","State the target: this task in under a minute.","Frustration is not a spec — give them one."],"focus":["audience","precision"],"placeholder":"Admitting a routine patient takes 11 clicks across 4 screens today —"},
    {"id":"audience-doc-mid-22","level":"mid","profession":"doctor","title":"Through the interpreter","scenario":"You're updating a family through a phone interpreter. Your normal update style — long compound sentences, parenthetical caveats — falls apart in interpretation. Every sentence you say will be relayed one at a time.","task":"Rewrite a 3-sentence update as short, single-idea sentences that survive interpretation.","tips":["One idea per sentence, no subclauses.","Pause points are part of the writing — mark where you'll stop.","Address the family, not the interpreter."],"focus":["audience","clarity"]},
    {"id":"audience-doc-mid-23","level":"mid","profession":"doctor","title":"The reporter's question","scenario":"A local reporter, cleared by the hospital, asks you about emergency department wait times. Your inner answer involves triage categories and surge staffing models. The reader of tomorrow's article wants to know: will I be seen if I'm really sick?","task":"Write a 2-3 sentence quote-ready answer to the reader's real question.","tips":["Answer the fear first: the sickest are seen immediately, always.","Use numbers a lay reader can hold — hours, not percentiles.","Assume every sentence will be printed alone."],"focus":["audience","clarity"],"placeholder":"If you come in seriously ill, you are seen immediately — the wait applies to less urgent problems."},
    {"id":"audience-doc-mid-24","level":"mid","profession":"doctor","title":"The teaching session pitched right","scenario":"You're teaching Thursday's session to first-month interns. Your slides were made for fellows and open with controversies in the literature. Interns need the reliable basics first — what to do at 3am when they're alone.","task":"Write the session's 2-sentence framing, recalibrated to what interns need this month.","tips":["Pitch to their next shift, not to the field's frontier.","Name what they'll be able to handle alone after the hour.","Advanced nuance is a distraction until the basics are automatic."],"focus":["audience","structure"]},
    {"id":"audience-doc-mid-25","level":"mid","profession":"doctor","title":"The donor update","scenario":"A local foundation funded your clinic's new equipment last year and asked for an update. Your draft reads like a utilization report. Donors gave to help people; they want to see what their money did in human terms — honestly, without spin.","task":"Write a 3-sentence update translating utilization into what changed for patients.","tips":["Lead with the human outcome, backed by one honest number.","Gratitude is fine; specifics are what earn renewal.","No inflation — donors detect puffery faster than auditors."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-doc-mid-01","level":"mid","profession":"doctor","title":"Three buckets for the chief","scenario":"Your monthly meeting with the department chief is in an hour. Your notes are a scrawl of eleven items: two staffing gaps, a broken scanner, three resident issues, a family complaint, a protocol delay, and assorted grievances. Read as a list, it sounds like whining.","task":"Group the eleven items into at most three labeled buckets and write the one-sentence headline for each.","tips":["Find the governing categories: staffing, equipment, education — whatever truly carries them.","Lead each bucket with its ask, not its story.","Anything that fits no bucket probably doesn't belong in this meeting."],"focus":["structure","clarity"],"placeholder":"Three things today: a staffing decision, an equipment escalation, and a resident concern."},
    {"id":"structure-doc-mid-02","level":"mid","profession":"doctor","title":"SCQA for the infection-control committee","scenario":"You're proposing a change to how central lines are maintained on your unit. You have the data and the fix, but your last committee pitch rambled and died in discussion. This time you want a tight opening: situation, complication, question, answer.","task":"Write a 4-sentence SCQA opening for the proposal.","tips":["Situation: one sentence of shared, undisputed context.","Complication: the change or problem that demands action now.","Question and answer: pose the question the room is asking, then answer it — that's your proposal."],"focus":["structure","impact"],"placeholder":"Our line-infection rate held steady for two years. In the last quarter it doubled."},
    {"id":"structure-doc-mid-03","level":"mid","profession":"doctor","title":"PREP for the evening-hours question","scenario":"In the leadership meeting, the operations director turns to you: \"Should the clinic extend to evening hours?\" You have a view — yes, two evenings a week — but you tend to think aloud in these moments and bury your own answer.","task":"Give a spoken PREP answer: Point, Reason, Example, Point — in 4-5 sentences.","tips":["Point first: yes, two evenings a week, starting with a pilot.","One reason, one concrete example — not four of each.","Restate the point at the end so the room leaves with it."],"focus":["structure","clarity"]},
    {"id":"structure-doc-mid-04","level":"mid","profession":"doctor","title":"The family conference agenda","scenario":"Tomorrow's family conference has four siblings, two of whom disagree about their mother's care. Without structure it will become ninety minutes of circular argument. You need one governing message and no more than three topics, in an order that builds.","task":"Write the governing message and the three agenda topics as you would state them at the start.","tips":["The governing message is the sentence everything else serves.","Order the topics so facts come before decisions.","Announcing the structure out loud is what makes it hold."],"focus":["structure","audience"],"placeholder":"Our goal today is to agree on the next step for your mother's care. I'd like to cover three things —"},
    {"id":"structure-doc-mid-05","level":"mid","profession":"doctor","title":"The rounds template","scenario":"Your residents each present patients differently — some lead with labs, some with the overnight narrative, some meander. Rounds run forty minutes over. You're writing the one-slide template that every presentation on your service will follow.","task":"Write the presentation template as an ordered list of 3-4 elements, each with a one-line description.","tips":["Order for the listener's decision: headline status, active issues, today's plan.","Cap each element — a template without limits isn't one.","The template should make the fifth patient sound like the first."],"focus":["structure","concision"]},
    {"id":"structure-doc-mid-06","level":"mid","profession":"doctor","title":"Structuring the M&M case","scenario":"You're building next month's morbidity and mortality presentation about a missed deterioration. A pure chronology invites hindsight bias and blame. You want a structure that carries the audience from what happened to why the system allowed it to what changes.","task":"Write the three section headers of the presentation, each phrased as a full-sentence takeaway.","tips":["Full-sentence headers force each section to have a point.","Move from event to system cause to fix — not from blame to blame.","The last header should be the change the audience votes on."],"focus":["structure","impact"]},
    {"id":"structure-doc-mid-07","level":"mid","profession":"doctor","title":"Nine complaints, three themes","scenario":"The quarterly patient-experience report lists nine free-text complaints about your clinic: three about phone hold times, two about confusing discharge instructions, two about parking, one about a rude interaction, one about billing. Presented raw, the committee will fixate on the rude one.","task":"Group the nine complaints into themes and write a one-sentence summary of each theme with its count.","tips":["Group by what would fix them, not by how they were worded.","Counts turn anecdotes into signals.","Name the outlier as an outlier so it doesn't hijack the meeting."],"focus":["structure","precision"],"placeholder":"Three themes this quarter: access (5 complaints), communication (3), and one isolated conduct issue."},
    {"id":"structure-doc-mid-08","level":"mid","profession":"doctor","title":"Discharge instructions in three buckets","scenario":"Your unit's discharge instructions are a page of undifferentiated bullet points — medications mixed with appointments mixed with warning signs. Patients retain almost none of it. You're redesigning the structure, not the content.","task":"Define the three buckets the instructions will use and write the one-line header for each.","tips":["Structure around the patient's questions: what do I take, where do I go, when do I worry?","Warning signs deserve their own bucket — never bury them.","Three memorable groups beat twelve accurate bullets."],"focus":["structure","audience"]},
    {"id":"structure-doc-mid-09","level":"mid","profession":"doctor","title":"The grand rounds spine","scenario":"You're giving grand rounds in six weeks on your unit's readmission-reduction work. You have forty slides of material and no spine. Before touching slides, you need the governing idea and the three sections that carry it.","task":"Write the governing idea as one sentence and the three section titles that support it.","tips":["The governing idea is the sentence you'd keep if allowed only one.","Every section must carry weight for that sentence — orphans get cut.","Write the spine before the slides, always."],"focus":["structure","clarity"]},
    {"id":"structure-doc-mid-10","level":"mid","profession":"doctor","title":"SCQA for the night-nurse ask","scenario":"You're emailing the director of nursing to request a second night nurse for the unit. Your previous emails on this listed incidents in the order they happened and got sympathetic non-answers. This one will be built: situation, complication, question, answer.","task":"Write the 4-sentence SCQA email body.","tips":["Situation and complication set up the ask; keep them to one sentence each.","The answer is your request, specific: one additional night nurse, seven nights.","Structure converts a complaint into a decision request."],"focus":["structure","impact"],"placeholder":"Our night staffing has been one nurse per twelve patients for two years. Three months ago acuity changed."},
    {"id":"structure-doc-mid-11","level":"mid","profession":"doctor","title":"Three points for the struggling resident","scenario":"You're meeting a resident whose performance is slipping — late notes, missed follow-ups, a curt interaction with nursing. You have a page of examples. If you unload all of it, nothing lands. The meeting needs at most three points, ordered.","task":"Choose and write the three points as you would open the meeting, one sentence each.","tips":["Pick the three that matter most for patients; park the rest.","Order from most fixable to most sensitive.","Announce there are three — it tells them the criticism has a floor."],"focus":["structure","clarity"]},
    {"id":"structure-doc-mid-12","level":"mid","profession":"doctor","title":"Sequencing the multidisciplinary meeting","scenario":"You're chairing a complex-case meeting: surgery, rehab, social work, pharmacy, and the primary nurse, thirty minutes, one patient with competing priorities. Left unsequenced, the loudest specialty goes first and frames everything.","task":"Write the meeting sequence as 3-4 ordered steps with a time budget for each.","tips":["Sequence facts before opinions and options before decisions.","Give the quiet essentials — social work, nursing — protected slots.","State the decision the meeting must produce at the top."],"focus":["structure","audience"]},
    {"id":"structure-doc-mid-13","level":"mid","profession":"doctor","title":"The debrief in three movements","scenario":"Yesterday's resuscitation was chaotic — right outcome, messy process. You're leading the team debrief this afternoon. Unstructured debriefs on your unit turn into either silence or blame. You want three fixed movements: what happened, why, what changes.","task":"Write the one-sentence prompt you'll use to open each of the three movements.","tips":["Facts first, and only facts — hold interpretations at the door.","The \"why\" movement asks about systems, not villains.","Close with one owned change, not a vow to do better."],"focus":["structure","clarity"],"placeholder":"First, just the timeline: what did each of us see and do, in order?"},
    {"id":"structure-doc-mid-14","level":"mid","profession":"doctor","title":"PREP on readmissions","scenario":"The CMO stops you after a meeting: \"Your readmission number moved the wrong way — what's going on?\" You have thirty seconds standing in a hallway. You know the driver: patients discharged without follow-up booked, since the coordinator role went vacant.","task":"Give a spoken PREP answer in 3-4 sentences: point, reason, example, point.","tips":["Point: the number rose because follow-ups stopped being booked.","One example makes it concrete: a named (anonymized) bounce-back.","End with the point plus the fix — refill the role."],"focus":["structure","concision"]},
    {"id":"structure-doc-mid-15","level":"mid","profession":"doctor","title":"The flu-season memo skeleton","scenario":"You owe leadership the clinic's flu-season plan. Your predecessor's version was six pages nobody read. Yours will be one page with a governing sentence and three sections: staffing, patient flow, communication.","task":"Write the governing sentence and the one-line summary that will sit atop each of the three sections.","tips":["The governing sentence states the plan's promise in plain terms.","Each section summary is its conclusion, not its topic.","A reader of only four sentences should know the whole plan."],"focus":["structure","concision"],"placeholder":"The clinic will absorb flu season without cancelling routine care, through three changes."},
    {"id":"structure-doc-mid-16","level":"mid","profession":"doctor","title":"Sorting the error reports","scenario":"You're presenting six months of medication-error reports to the safety committee — 41 events. Listed chronologically, they're noise. Grouped, they tell a story: most cluster around two failure points, transcription at admission and look-alike packaging.","task":"Write the 2-3 sentence framing that presents the grouped finding instead of the list.","tips":["Lead with the pattern: 41 events, two clusters.","The grouping IS the analysis — chronology hides it.","End with where the committee's attention should go."],"focus":["structure","precision"],"placeholder":"Of 41 events, 29 trace to two failure points."},
    {"id":"structure-doc-mid-17","level":"mid","profession":"doctor","title":"The service-line proposal pyramid","scenario":"You're pitching a new outpatient service line to the executive team: twenty minutes, then questions. Your material sprawls — demand data, staffing model, space, financials. Pyramid it: one governing recommendation, at most three supporting pillars.","task":"Write the governing recommendation and name the three pillars, one line each.","tips":["The recommendation includes the ask: approve, fund, when.","Choose pillars by what the executives doubt, not by what you know.","Everything not under a pillar goes to the appendix."],"focus":["structure","impact"]},
    {"id":"structure-doc-mid-18","level":"mid","profession":"doctor","title":"The patient FAQ that answers in order","scenario":"You're writing the FAQ sheet for patients starting a common treatment at your clinic. The current sheet answers questions in the order staff thought of them. Patients ask in a predictable order: does it work, does it hurt, what do I do, when do I call?","task":"List the FAQ's first four questions in the patient's order, with a one-sentence answer to the first.","tips":["Sequence by the patient's anxiety, not the clinic's workflow.","Every answer starts with the answer.","The call-us threshold question must be findable in five seconds."],"focus":["structure","audience"]},
    {"id":"structure-doc-mid-19","level":"mid","profession":"doctor","title":"The handoff that holds its shape","scenario":"Your unit's verbal handoffs wander — background, then a lab value, then back to background. You're standardizing the spoken structure: headline, active issues, if-then contingencies. Tonight you model it for the sickest patient.","task":"Write the model handoff in 3-4 sentences following that fixed order.","tips":["Headline: who this patient is and their trajectory in one sentence.","Contingencies are the payload: if X happens, do Y.","A fixed order lets the listener notice what's missing."],"focus":["structure","precision"],"placeholder":"Headline: 74-year-old, day two after surgery, improving but fragile overnight."},
    {"id":"structure-doc-mid-20","level":"mid","profession":"doctor","title":"Twelve ideas, three priorities","scenario":"Your unit's improvement brainstorm produced twelve sticky-note ideas, from repainting the family room to overhauling the handoff. The team meets Friday expecting direction. Twelve priorities means zero priorities.","task":"Write the 2-3 sentence Friday message that names the three chosen priorities and what happens to the other nine.","tips":["Choose by impact and feasibility, and say that's the filter.","Honor the parked nine explicitly — parked is not rejected.","One owner per priority, named."],"focus":["structure","clarity"]},
    {"id":"structure-doc-mid-21","level":"mid","profession":"doctor","title":"The recommendation letter that argues","scenario":"You're writing a fellowship recommendation for your best senior resident. Your draft is chronological — intern year, then second year — and reads like a transcript. A strong letter argues one claim and organizes evidence under it.","task":"Write the letter's governing claim and the 2-3 evidence themes that will support it.","tips":["The claim ranks her: top-five-percent specific, not warmly generic.","Themes beat chronology: judgment, ownership, teaching.","Every anecdote must serve the claim or leave the letter."],"focus":["structure","impact"]},
    {"id":"structure-doc-mid-22","level":"mid","profession":"doctor","title":"The surveyor's question","scenario":"An accreditation surveyor asks you: \"How does your unit ensure critical results are acted on?\" You know the answer in fragments — the alert system, the escalation policy, the audit. Fragments sound like improvisation. A structured answer sounds like a system.","task":"Give a 3-4 sentence spoken answer with an announced structure.","tips":["Announce the shape: we do three things.","Order: detection, escalation, verification.","Close by naming how you know it works — the audit."],"focus":["structure","clarity"],"placeholder":"Three layers. First, every critical result triggers a direct call —"},
    {"id":"structure-doc-mid-23","level":"mid","profession":"doctor","title":"SCQA for telehealth follow-ups","scenario":"You want the clinic to move routine post-visit checks to telehealth. Half your colleagues are skeptical. Your pitch at Thursday's meeting gets five minutes. You'll build it as SCQA so the skeptics hear the problem before the proposal.","task":"Write the four SCQA sentences you'll open with.","tips":["Situation: the follow-up load everyone already feels.","Complication: no-show rates and wasted slots — the shared pain.","The answer proposes a bounded pilot, not a revolution."],"focus":["structure","impact"]},
    {"id":"structure-doc-mid-24","level":"mid","profession":"doctor","title":"The code debrief, structured cold","scenario":"A code on the ward this morning went technically fine but communication failed — two people gave orders at once, one order was never acknowledged. The team debriefs in twenty minutes while it's raw. Structure is what keeps raw from becoming personal.","task":"Write the 3-part structure you'll announce at the start, one sentence per part.","tips":["Announce the parts before anyone speaks — it's a container for emotion.","Separate what the timeline shows from what people felt.","End on one process change with an owner."],"focus":["structure","audience"]},
    {"id":"structure-doc-mid-25","level":"mid","profession":"doctor","title":"The annual update in pyramid form","scenario":"You present your service's annual update to the department in ten minutes: volumes, quality results, staffing changes, next year's plan. Last year you ran through it list-wise and got no questions — the polite silence of an audience that absorbed nothing.","task":"Write the governing sentence of this year's update and the three headers beneath it.","tips":["Find the year's one-sentence story — growth, recovery, strain — and lead with it.","Make each header a claim the section proves.","Ten minutes carries one idea well or ten ideas not at all."],"focus":["structure","impact"],"placeholder":"The story of this year: we grew 20% without losing our quality numbers — but the seams are showing."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-doc-mid-01","level":"mid","profession":"doctor","title":"The hedged consult reply","scenario":"A colleague asked whether a patient can start anticoagulation. Your draft answer is a fog of hedges: \"it may possibly be reasonable to consider,\" \"I would tend to think,\" \"perhaps.\" The colleague needs a decision, not your internal weather.","task":"Rewrite the reply in 1-2 sentences with every hedge removed.","tips":["Delete \"may possibly,\" \"tend to,\" \"perhaps\" — say what you mean.","If you're genuinely unsure, name the one thing that would decide it.","One clear caveat is precision; five hedges are evasion."],"focus":["concision","clarity"],"placeholder":"Yes, start anticoagulation today — the bleeding risk is low and the clot risk isn't."},
    {"id":"concise-doc-mid-02","level":"mid","profession":"doctor","title":"Halving the email to the chief","scenario":"Your email to the department chief requesting new equipment runs eight sentences of buildup before the ask. The chief reads fast and skims the rest. Every extra sentence lowers the odds she reaches your point.","task":"Cut the message to three sentences that keep only the ask, the reason, and the deadline.","tips":["Keep the ask, the strongest reason, the date. Cut the rest.","Delete throat-clearing openers like \"I wanted to reach out.\"","If a sentence doesn't move the decision, it's ballast."],"focus":["concision","impact"]},
    {"id":"concise-doc-mid-03","level":"mid","profession":"doctor","title":"The nominalized QI report","scenario":"Your quality report is thick with nominalizations: \"the implementation of the utilization of the checklist resulted in a reduction.\" Buried inside is a simple fact — the checklist cut errors. The abstraction makes it sound like nothing happened.","task":"Rewrite the sentence with live verbs and no nominalizations.","tips":["Turn \"implementation of\" and \"reduction\" back into verbs: we used, it cut.","Name the actor: who did what to what.","Nominalizations hide agency and double the word count."],"focus":["concision","clarity"],"placeholder":"After we added the checklist, errors dropped by half."},
    {"id":"concise-doc-mid-04","level":"mid","profession":"doctor","title":"The meta-commentary in the handoff note","scenario":"Your written handoff opens with \"I just wanted to quickly note that I think it's probably worth mentioning that...\" — three lines of preamble before a single clinical fact. The night team is scanning for what to do.","task":"Rewrite the note stripped of all meta-commentary, starting with the clinical fact.","tips":["Delete every phrase about the note itself: \"just wanted to note.\"","Start with the fact or the action, not the announcement of it.","The reader wants the content, not a trailer for it."],"focus":["concision","clarity"]},
    {"id":"concise-doc-mid-05","level":"mid","profession":"doctor","title":"Redundant pairs in the family letter","scenario":"Your letter to a family is full of doublets: \"each and every,\" \"first and foremost,\" \"safe and secure,\" \"full and complete.\" They pad the letter and slow an already anxious reader.","task":"Rewrite a 3-sentence passage removing every redundant pair.","tips":["Pick one word from each doublet; the other adds nothing.","Read it aloud — the pairs will announce themselves.","Shorter reads as more confident, not less caring."],"focus":["concision","clarity"]},
    {"id":"concise-doc-mid-06","level":"mid","profession":"doctor","title":"The overlong rounds summary","scenario":"Your verbal summary for a stable patient on rounds runs ninety seconds — the same length as the crashing patient next door. The team's attention is a fixed budget, and you're spending it on someone who's fine.","task":"Compress the stable-patient summary to two sentences: status and plan.","tips":["Stable patients get one line of status and one of plan.","Save the detail budget for the patients who need it.","Length should track acuity, not habit."],"focus":["concision","structure"],"placeholder":"Bed 9 is stable, pain controlled, eating. Plan: home tomorrow if the morning labs hold."},
    {"id":"concise-doc-mid-07","level":"mid","profession":"doctor","title":"Filler in the committee pitch","scenario":"You're rehearsing your two-minute committee pitch and it's stuffed with filler: \"basically,\" \"actually,\" \"at the end of the day,\" \"in terms of.\" The content is good; the filler makes it sound uncertain.","task":"Rewrite a 3-sentence chunk of the pitch with every filler word cut.","tips":["Target the reflex words: basically, actually, essentially, in terms of.","Each one deleted makes the claim sound more certain.","Read the before and after aloud to hear the difference."],"focus":["concision","impact"]},
    {"id":"concise-doc-mid-08","level":"mid","profession":"doctor","title":"The apology that won't end","scenario":"You're writing to a family after a long wait in clinic. Your draft apologizes six times across four sentences. Past a point, repeated apology stops reassuring and starts sounding like you fear a complaint.","task":"Rewrite the message with one sincere apology and one concrete fix.","tips":["Apologize once, specifically, then move to the fix.","Over-apology shifts focus from them to your anxiety.","A named action repairs more than a fifth sorry."],"focus":["concision","impact"],"placeholder":"I'm sorry you waited two hours today. Here's what we're changing so it doesn't happen again —"},
    {"id":"concise-doc-mid-09","level":"mid","profession":"doctor","title":"The bloated protocol paragraph","scenario":"The new protocol's key step is written as a 60-word sentence with three subclauses. Nurses will read it at 3am. Every clause they must parse is a chance to act on the wrong one.","task":"Rewrite the step as one instruction under 20 words, or as a short numbered sequence.","tips":["One action per sentence; break the compound into steps.","Front-load the verb: what to do comes first.","At 3am, brevity is a safety feature."],"focus":["concision","clarity"]},
    {"id":"concise-doc-mid-10","level":"mid","profession":"doctor","title":"The over-caveated recommendation","scenario":"You're recommending a treatment change to a colleague, but you've wrapped it in so many caveats — \"depending on many factors,\" \"of course this is just my view,\" \"there are always exceptions\" — that no recommendation survives.","task":"Rewrite it as a clear recommendation with at most one genuine caveat.","tips":["State the recommendation plainly, then one real caveat if it exists.","Ritual caveats signal insecurity, not rigor.","The reader can ask about exceptions — don't preload them all."],"focus":["concision","clarity"]},
    {"id":"concise-doc-mid-11","level":"mid","profession":"doctor","title":"The wordy portal reply","scenario":"A patient asked a simple portal question — can she take an over-the-counter pain reliever with her prescription. Your draft is a paragraph of context before the yes. She wants the answer, then the caveat.","task":"Rewrite the reply as two sentences: the answer, then the one thing to watch.","tips":["Answer first: yes, or yes with a limit.","One caveat that matters, not a pharmacology lecture.","Patients trust brevity that's clearly complete."],"focus":["concision","audience"],"placeholder":"Yes, that's fine to take together. Keep it to the label dose and stop if your stomach gets upset."},
    {"id":"concise-doc-mid-12","level":"mid","profession":"doctor","title":"Trimming the incident timeline","scenario":"Your incident report timeline includes every routine event of the shift alongside the three that mattered. The committee has to hunt for the relevant moments in a thicket of \"08:15 — vitals taken, normal.\"","task":"Rewrite the timeline keeping only the events that bear on what went wrong.","tips":["Include an event only if its absence would change the analysis.","Routine, normal, uneventful — cut unless it's the point.","A tight timeline reads as a clear head."],"focus":["concision","precision"]},
    {"id":"concise-doc-mid-13","level":"mid","profession":"doctor","title":"The over-explained no","scenario":"A resident asked to leave early Friday and the answer is no — the service is short-staffed. Your draft justification runs a full paragraph of staffing logic, which invites negotiation of each point.","task":"Write a 2-sentence no: the answer and one honest reason.","tips":["Say no clearly, then give the single real reason.","A wall of justification signals the no is negotiable.","Respect them with a clean answer, not a defense brief."],"focus":["concision","clarity"]},
    {"id":"concise-doc-mid-14","level":"mid","profession":"doctor","title":"The padded abstract","scenario":"You're submitting an abstract for your readmission project to a conference, and it's 300 words of setup for a 40-word finding. Reviewers skim hundreds; the padding buries what you actually showed.","task":"Rewrite the abstract's core to lead with the finding in two tight sentences.","tips":["Lead with the result and its size, not the background.","Cut every sentence a reviewer already knows.","The finding is the abstract; everything else is scaffolding."],"focus":["concision","precision"],"placeholder":"A five-item discharge checklist cut 30-day readmissions from 18% to 11% over six months."},
    {"id":"concise-doc-mid-15","level":"mid","profession":"doctor","title":"The verbose voicemail","scenario":"You're leaving a voicemail for a patient's family with a scan result. Your first attempt rambles for ninety seconds and the callback number comes last, when they've stopped listening.","task":"Write a 3-sentence voicemail: who you are, the essential point, the callback number.","tips":["Identify yourself and the reason in one breath.","One clear point — don't deliver nuance to a machine.","Callback number early and slow, then repeat it."],"focus":["concision","clarity"],"placeholder":"This is Dr. Lee from the hospital calling about your father's scan — good news overall."},
    {"id":"concise-doc-mid-16","level":"mid","profession":"doctor","title":"The overstuffed slide","scenario":"Your committee slide has 140 words in nine bullets. You'll be talking over it, so the slide competes with your voice. The audience reads instead of listens, and gets neither.","task":"Rewrite the slide's content as a single headline plus at most three phrases.","tips":["The headline states the takeaway; the phrases prompt it.","If they can read it, they won't hear you — so keep it sparse.","Your voice carries the detail; the slide carries the anchor."],"focus":["concision","impact"]},
    {"id":"concise-doc-mid-17","level":"mid","profession":"doctor","title":"The circular meeting minutes","scenario":"You're writing minutes for the unit meeting and the draft records every digression and repeated point. People will search these for decisions and actions and drown in the retelling.","task":"Rewrite one agenda item's minutes as just the decision and the owner-plus-date.","tips":["Minutes capture decisions and actions, not the conversation.","Each item: what was decided, who does what, by when.","Discussion is context; only the decision is a record."],"focus":["concision","structure"],"placeholder":"Decision: adopt the new sepsis screen June 1. Owner: Dr. Adams to train staff by May 25."},
    {"id":"concise-doc-mid-18","level":"mid","profession":"doctor","title":"The overwritten condolence","scenario":"You're writing to the family of a patient who died. Your draft, trying hard, piles on ornate phrasing that distances rather than comforts. Grief wants plain, true sentences.","task":"Write three plain sentences of condolence, cutting every ornate flourish.","tips":["Plain words carry more weight than elaborate ones here.","Say something specific and true about the person if you can.","Restraint reads as sincerity; excess reads as a template."],"focus":["concision","audience"]},
    {"id":"concise-doc-mid-19","level":"mid","profession":"doctor","title":"The redundant order comment","scenario":"You're adding a comment to an order that already says what it does. Your comment restates the order, then adds \"please ensure this is done as ordered\" — noise that trains readers to skip your comments.","task":"Rewrite the comment to add only the one thing the order doesn't already say, or cut it entirely.","tips":["A comment earns its place by adding non-obvious information.","Never restate the order; the order already states it.","If there's nothing to add, the best comment is none."],"focus":["concision","clarity"]},
    {"id":"concise-doc-mid-20","level":"mid","profession":"doctor","title":"The long way to a short answer","scenario":"In a leadership meeting you're asked if the unit can take a new admission. You know the answer is no until noon. Instead you narrate the whole bed situation and the room waits for the verb.","task":"Answer in one sentence: the answer plus the single controlling fact.","tips":["Lead with no; attach the one fact that governs it.","The room can ask for detail — give the verdict first.","A meeting rewards the person who lands the point fast."],"focus":["concision","impact"],"placeholder":"Not until noon — we're full until two discharges clear."},
    {"id":"concise-doc-mid-21","level":"mid","profession":"doctor","title":"Trimming the teaching point","scenario":"You want to leave residents with one teaching point after a case, but your draft delivers it in a 5-sentence mini-lecture with three tangents. They'll remember none of it.","task":"Distill the teaching point to one memorable sentence.","tips":["One sentence they could repeat to a colleague tomorrow.","Cut the tangents; a second point erases the first.","Memorable beats comprehensive for teaching."],"focus":["concision","impact"]},
    {"id":"concise-doc-mid-22","level":"mid","profession":"doctor","title":"The bloated referral reason","scenario":"Your referral's \"reason\" field contains a paragraph copied from your note. The receiving specialist's triage nurse needs one line to sort urgency, and your paragraph forces them to read and interpret.","task":"Rewrite the referral reason as a single line stating the question and urgency.","tips":["One line: what you're asking and how soon.","The full note attaches; the reason field is the headline.","Triage runs on clarity, not completeness."],"focus":["concision","precision"],"placeholder":"Assess for surgical repair; symptoms worsening over 3 weeks — routine-urgent."},
    {"id":"concise-doc-mid-23","level":"mid","profession":"doctor","title":"The over-qualified pager message","scenario":"You're paging a specialist and your message spends its characters on courtesy and context before the actual need. On a pager, character count is real and the recipient wants the ask, fast.","task":"Write the page in under 20 words: who, what you need, callback.","tips":["Every word competes for a tiny screen — spend them on the ask.","Skip the pleasantries a page doesn't have room for.","Name, need, number — in that order."],"focus":["concision","clarity"],"placeholder":"Dr. Vance, need surgical eval bed 12, possible obstruction. Call ext. 4471."},
    {"id":"concise-doc-mid-24","level":"mid","profession":"doctor","title":"The essay in the peer feedback","scenario":"You're giving written feedback to a resident on a note they wrote. Your comment runs three paragraphs where one specific fix would land better. They'll skim it and miss the actionable part.","task":"Rewrite the feedback as one sentence naming the specific change to make.","tips":["Name the one change, concretely, so they can act tonight.","A short pointed note gets read; an essay gets deferred.","Save the broader lesson for a conversation, not a comment box."],"focus":["concision","clarity"]},
    {"id":"concise-doc-mid-25","level":"mid","profession":"doctor","title":"Halving the discharge instructions","scenario":"Your discharge instruction sheet for a common condition is a full page of prose. Studies on your own unit show patients read the top third. Everything below the fold is effort spent on no one.","task":"Cut the instructions to the five things that actually change what the patient does at home.","tips":["Keep only what changes behavior: meds, appointments, red flags.","Cut the reassurance and the physiology.","If it doesn't tell them what to do, it can go."],"focus":["concision","audience"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-doc-mid-01","level":"mid","profession":"doctor","title":"\"A lot better\" isn't a number","scenario":"You're updating the department on your unit's wait times and your draft says patients are \"waiting a lot less than before.\" The chief will ask how much and by when, and \"a lot\" will evaporate under the question.","task":"Rewrite the claim with a specific number, baseline, and timeframe.","tips":["Replace \"a lot\" with the actual figure and its comparison.","Anchor to a date: from when to when.","A number invites belief; a vague intensifier invites doubt."],"focus":["precision","impact"],"placeholder":"Median wait fell from 47 to 31 minutes between January and June."},
    {"id":"precision-doc-mid-02","level":"mid","profession":"doctor","title":"The vague safety claim","scenario":"Your QI slide says the new protocol made things \"significantly safer.\" The committee includes people who will ask what \"significantly\" means and whether it's the statistical kind. Undefined, the word is empty.","task":"Rewrite the claim with the specific safety measure and its change.","tips":["Name the measure: falls, errors, infections — and the number.","Avoid \"significant\" unless you mean it statistically and can defend it.","Specificity is what separates a result from a hope."],"focus":["precision","clarity"],"placeholder":"Falls dropped from 9 to 3 per 1,000 patient-days after the protocol started."},
    {"id":"precision-doc-mid-03","level":"mid","profession":"doctor","title":"From data table to one insight","scenario":"You have a table of monthly infection rates for the committee, and your instinct is to present all twelve rows. The committee doesn't want the table; they want the one thing it means.","task":"Write the single-sentence insight the table supports, with the number that proves it.","tips":["Say what the data means before showing what it is.","One insight, one supporting figure — the table is backup.","If you can't state the insight, you don't yet have one."],"focus":["precision","impact"],"placeholder":"Infections held flat until March, then doubled — the change tracks exactly with the new supplier."},
    {"id":"precision-doc-mid-04","level":"mid","profession":"doctor","title":"What, so what, now what","scenario":"You're reporting a finding to leadership: readmissions rose last quarter. Your draft states the what and stops, leaving leadership to guess the significance and the action. A finding without a so-what and now-what is just a data point.","task":"Write three sentences: the finding, why it matters, and what you propose to do.","tips":["What: the finding with its number.","So what: the consequence in terms leadership feels.","Now what: your specific proposed action."],"focus":["precision","structure"],"placeholder":"Readmissions rose from 11% to 16% last quarter. At our volume that's 40 avoidable admissions —"},
    {"id":"precision-doc-mid-05","level":"mid","profession":"doctor","title":"Passing the skeptic test","scenario":"You're claiming the new discharge process saves nursing time. A skeptical nurse manager will ask how you know — measured, or assumed? Your draft asserts the saving without a source, and the skeptic will win.","task":"Rewrite the claim so it names how the saving was measured.","tips":["Attach the method: timed on how many discharges, over what period.","A measured number survives the skeptic; an estimate should say so.","Name your evidence before someone asks for it."],"focus":["precision","impact"]},
    {"id":"precision-doc-mid-06","level":"mid","profession":"doctor","title":"\"Soon\" and \"shortly\" to a family","scenario":"A family keeps asking when their mother's results will be ready and your reflex answers are \"soon\" and \"shortly.\" To an anxious family those words are meaningless and, worse, they erode trust when the vague window passes.","task":"Rewrite the answer with a concrete time and what happens if it slips.","tips":["Give a real time window: by 4pm, not soon.","Say who will tell them and how.","If it might slip, say so now — surprises cost more than delays."],"focus":["precision","audience"],"placeholder":"The results should be back by 4pm. I'll come find you the moment they are —"},
    {"id":"precision-doc-mid-07","level":"mid","profession":"doctor","title":"The imprecise medication instruction","scenario":"Your written instruction to a patient says to take the medication \"as needed for pain.\" That leaves maximum dose, minimum interval, and the ceiling undefined — the exact gaps that cause overdoses at home.","task":"Rewrite the instruction with specific dose, interval, and daily maximum.","tips":["Specify the number, the how-often, and the never-exceed.","\"As needed\" needs a ceiling to be safe.","Precision here is patient safety, not pedantry."],"focus":["precision","clarity"],"placeholder":"Take one tablet every 6 hours if you have pain, up to 4 tablets in 24 hours — no more."},
    {"id":"precision-doc-mid-08","level":"mid","profession":"doctor","title":"The unsupported staffing claim","scenario":"You're arguing to leadership that the unit is understaffed, and your draft says the team is \"stretched dangerously thin.\" Leadership hears that from every unit. Without a number and a consequence, it's noise.","task":"Rewrite the claim with the ratio, the benchmark, and the measured consequence.","tips":["Give your ratio versus the recommended one.","Tie it to a countable outcome: missed assessments, delayed meds.","\"Dangerous\" is a claim; the incident count is evidence."],"focus":["precision","impact"],"placeholder":"We're running 1 nurse to 8 patients against a recommended 1-to-5, and missed medication windows tripled last month."},
    {"id":"precision-doc-mid-09","level":"mid","profession":"doctor","title":"The scan result, precisely","scenario":"You're conveying a scan result to a colleague and your draft says the finding is \"probably nothing to worry about.\" The colleague needs to know what was seen, its size, and the actual recommendation — not your reassurance.","task":"Rewrite the summary with the specific finding, its size, and the recommended follow-up.","tips":["State what was found and its measurement.","Give the recommendation as an action and interval.","Reassurance is for the patient; the colleague needs the facts."],"focus":["precision","clarity"]},
    {"id":"precision-doc-mid-10","level":"mid","profession":"doctor","title":"The project result that overclaims","scenario":"Your handwashing campaign report says compliance is \"now excellent.\" The infection preventionist has the audit data and will check. If \"excellent\" is 78%, the gap between your word and the number damages your credibility for the next project.","task":"Rewrite the result with the audited compliance number and an honest read of it.","tips":["Use the audited figure, not the flattering adjective.","If the number is good, it speaks for itself; if it's partial, say so.","Overclaiming once taxes every future claim."],"focus":["precision","impact"],"placeholder":"Audited hand-hygiene compliance rose from 61% to 78% — real progress, still short of our 90% target."},
    {"id":"precision-doc-mid-11","level":"mid","profession":"doctor","title":"The insight buried in the trend","scenario":"You're showing leadership six months of length-of-stay data. The story isn't the average — it's that a specific patient type drives the whole increase. Your draft presents the average and hides the driver.","task":"Write the sentence that names the driver, with the numbers that isolate it.","tips":["Find the subgroup that moves the whole number.","State the driver, then the figure that proves it's the driver.","The average conceals; the driver is the insight."],"focus":["precision","structure"],"placeholder":"Overall stay rose half a day, but it's entirely one group: rehab-awaiting patients, up from 3 to 8 days."},
    {"id":"precision-doc-mid-12","level":"mid","profession":"doctor","title":"\"Frequently\" in the incident report","scenario":"Your incident report says the equipment failure happens \"frequently.\" The safety committee needs to prioritize among competing problems, and \"frequently\" gives them nothing to rank against. How frequently?","task":"Rewrite the sentence with the actual frequency and the period it covers.","tips":["Count it: how many times, over how long.","A rate lets the committee prioritize; an adverb doesn't.","If you don't know the count, say you'll find it — don't estimate up."],"focus":["precision","clarity"],"placeholder":"The pump alarmed falsely 14 times in the past two weeks — roughly once a shift."},
    {"id":"precision-doc-mid-13","level":"mid","profession":"doctor","title":"The prognosis a family can hold","scenario":"A family asks how long recovery will take and you say \"it varies\" and \"everyone's different.\" Both are true and both are useless to people trying to plan work and childcare. They need a realistic range with honest uncertainty.","task":"Write a 2-sentence answer with a realistic range and a clear marker of what would change it.","tips":["Give a range, not a point — but a real range, in weeks.","Name the milestone that would move the estimate.","Honest uncertainty is specific: here's what we watch."],"focus":["precision","audience"]},
    {"id":"precision-doc-mid-14","level":"mid","profession":"doctor","title":"The vague budget ask","scenario":"You're requesting funds for unit improvements and your draft asks for \"adequate resources to address ongoing needs.\" Finance can't approve a fog. They need a figure, a line-item purpose, and a return.","task":"Rewrite the ask with a specific amount, what it buys, and the expected result.","tips":["Name the number and exactly what it funds.","Tie the spend to a measurable outcome finance values.","\"Adequate resources\" is not a budget line."],"focus":["precision","impact"],"placeholder":"I'm requesting $40,000 for two infusion pumps, which would eliminate the daily borrowing that delays chemo starts."},
    {"id":"precision-doc-mid-15","level":"mid","profession":"doctor","title":"So what, for the tired committee","scenario":"You present that your unit's patient-satisfaction score rose two points. The committee's silent question is: so what — is two points real, and does it matter? Your draft states the number and sits down.","task":"Write the so-what: what the two-point rise means in patient or operational terms.","tips":["Translate the metric into something the committee cares about.","Say whether two points is signal or noise, honestly.","A number without a so-what is a fact nobody uses."],"focus":["precision","impact"]},
    {"id":"precision-doc-mid-16","level":"mid","profession":"doctor","title":"The evidence behind the protocol change","scenario":"You're proposing to change a standing order and a colleague asks what it's based on. Your draft says \"the latest thinking\" and \"best practice.\" Those phrases invite the question you're dodging: whose thinking, what evidence?","task":"Rewrite the justification citing the specific source and what it showed.","tips":["Name the guideline, study, or audit — and its finding.","\"Best practice\" without a source is an appeal to authority you don't have.","Specific evidence ends the debate faster than confident vagueness."],"focus":["precision","clarity"]},
    {"id":"precision-doc-mid-17","level":"mid","profession":"doctor","title":"The over-precise false certainty","scenario":"Trying to sound rigorous, your report states readmission risk as \"23.7%\" from a small sample where that decimal is meaningless. A sharp reader will see the false precision and distrust the whole report.","task":"Rewrite the figure at a precision the data actually supports, and say why.","tips":["Match the decimals to the sample — round when precision is fake.","State the uncertainty: roughly one in four, not 23.7%.","False precision reads as innumeracy, not rigor."],"focus":["precision","clarity"],"placeholder":"About one in four of these patients came back within 30 days — the sample's too small for a sharper figure."},
    {"id":"precision-doc-mid-18","level":"mid","profession":"doctor","title":"Naming the mechanism, not just the correlation","scenario":"Your report claims the new checklist \"caused\" the drop in errors, but the same month you also added a pharmacist. A skeptic will point out you can't separate the two. Your claim needs to acknowledge the confound.","task":"Rewrite the claim to state what you can and can't attribute, precisely.","tips":["Separate what changed together — don't credit one for both.","State the association honestly, then what would isolate the cause.","Acknowledging the confound is more persuasive than ignoring it."],"focus":["precision","impact"]},
    {"id":"precision-doc-mid-19","level":"mid","profession":"doctor","title":"The measurable resident goal","scenario":"You're setting an improvement goal for a resident and your draft says \"be more thorough with follow-ups.\" That can't be assessed and won't change behavior. It needs a specific, countable target.","task":"Rewrite the goal as a specific, measurable behavior with a timeframe.","tips":["Name the observable behavior and the standard.","Make it countable so you can both tell if it's met.","\"Be more thorough\" is a wish; a target is a plan."],"focus":["precision","clarity"],"placeholder":"For the next month: every discharged patient has a follow-up booked before they leave, checked at sign-out."},
    {"id":"precision-doc-mid-20","level":"mid","profession":"doctor","title":"The vague risk in consent","scenario":"You're explaining a procedure's risk and you say it's \"very rare\" and \"unlikely.\" The patient deserves a number they can weigh. \"Rare\" means different things to different people, and consent requires shared understanding.","task":"Rewrite the risk statement with a concrete frequency the patient can picture.","tips":["Give a frequency: about 1 in 500, not \"very rare.\"","Use a picture the patient can hold — per how many people.","Precision here is part of informed consent, not optional."],"focus":["precision","audience"],"placeholder":"This complication happens to about 1 in 500 people — rare, but not impossible, so here's what we watch for."},
    {"id":"precision-doc-mid-21","level":"mid","profession":"doctor","title":"The trend that needs a baseline","scenario":"You report that your unit did 40 procedures this month as a success. Without last month or the target, the committee can't tell if 40 is good, bad, or flat. A number floating without a baseline persuades no one.","task":"Rewrite the claim anchoring 40 to a baseline or target so its meaning is clear.","tips":["Every figure needs a comparison to mean anything.","Anchor to prior period or to the goal.","A lone number is a fact; a compared number is evidence."],"focus":["precision","impact"],"placeholder":"We did 40 procedures this month, up from 28 last month and against a capacity target of 45."},
    {"id":"precision-doc-mid-22","level":"mid","profession":"doctor","title":"The audit finding, sharpened","scenario":"Your hand-hygiene audit summary says compliance \"needs improvement.\" Leadership can't act on a euphemism. They need the number, the gap to target, and where the misses cluster.","task":"Rewrite the finding with the compliance rate, the target gap, and where it's failing.","tips":["State the rate and how far below target it sits.","Locate the failure: which shift, which role, which moment.","\"Needs improvement\" hides exactly the information that enables action."],"focus":["precision","structure"]},
    {"id":"precision-doc-mid-23","level":"mid","profession":"doctor","title":"The equipment case, quantified","scenario":"You want a second ultrasound machine and your draft says the shared one causes \"constant delays.\" Purchasing will ask for the delay in hours and the cost of that delay. Give them the arithmetic before they ask.","task":"Rewrite the case with quantified delay and its downstream cost.","tips":["Count the delay: how many hours, how many patients.","Translate delay into cost or bed-days purchasing understands.","\"Constant\" is felt; the count is fundable."],"focus":["precision","impact"],"placeholder":"The single machine creates about 6 hours of scan backlog daily, pushing 3-4 discharges past noon."},
    {"id":"precision-doc-mid-24","level":"mid","profession":"doctor","title":"The insight the graph almost shows","scenario":"You're presenting a graph of daily admissions and the real finding is a predictable Monday spike the graph shows but doesn't state. If you leave the audience to spot it, half will miss it. Say the insight the picture only implies.","task":"Write the one sentence that names the pattern and its operational implication.","tips":["State the pattern in words; don't make them decode the graph.","Add the so-what: what the Monday spike means for staffing.","A graph shows; a sentence tells — you need both."],"focus":["precision","impact"],"placeholder":"Admissions spike every Monday by about 40% — which is exactly when we're staffed lightest."},
    {"id":"precision-doc-mid-25","level":"mid","profession":"doctor","title":"The outcome claim that survives review","scenario":"You're writing the conclusion of your QI project for the committee. Your draft says the project was \"a success.\" A rigorous committee wants the pre/post numbers, the timeframe, and what remains. Give them a claim that survives scrutiny.","task":"Write a 2-sentence conclusion with pre/post figures, timeframe, and one honest caveat.","tips":["Lead with the before-and-after numbers over a stated period.","Add the caveat that a skeptic would raise — you raise it first.","A defensible claim outlasts a flattering one."],"focus":["precision","impact"],"placeholder":"Over six months, readmissions fell from 18% to 11%; the sample is small, so we're continuing to track it."}
  ],
  "executive-presence": [
    {"id":"presence-doc-mid-01","level":"mid","profession":"doctor","title":"Own the staffing recommendation","scenario":"Leadership asks how to cover the unit's growing night load. Your draft lays out three options — hire, redeploy, or extend shifts — with pros and cons and no recommendation. As the service lead, presenting a neutral menu abdicates the job they're paying you for.","task":"Rewrite the close to recommend one option and say why, while noting the trade-off.","tips":["State your recommendation as a recommendation, not an option C.","Give the one reason it beats the others.","A menu asks them to do your thinking; own it."],"focus":["impact","clarity"],"placeholder":"My recommendation is to hire one night nurse rather than extend shifts — it costs more but it's the only option that's sustainable past three months."},
    {"id":"presence-doc-mid-02","level":"mid","profession":"doctor","title":"Signposting the family update","scenario":"You're updating a family with a lot to cover: her condition, the plan, and a decision they'll need to make. Without signposting, it's a wall of information they can't navigate. Presence here is telling them the shape before the content.","task":"Write the 2-sentence opening that signposts the three things you'll cover.","tips":["Announce the structure: here are the three things I'll cover.","Signposting lets an anxious listener know where they are.","Structure spoken aloud reads as command of the situation."],"focus":["impact","structure"],"placeholder":"I want to cover three things: how she's doing, our plan for the week, and one decision I'll need your help with."},
    {"id":"presence-doc-mid-03","level":"mid","profession":"doctor","title":"Fact versus judgment in the M&M","scenario":"Presenting at M&M, your draft blends what happened with your interpretation so the room can't tell the timeline from your opinion. Presence is keeping the two visibly separate so the audience trusts your judgment because they can see your facts.","task":"Rewrite a passage that first states the facts, then clearly marks your judgment as judgment.","tips":["Give the facts flat, then say \"in my judgment\" and interpret.","Blending the two makes people doubt both.","Marking your opinion as opinion is a mark of authority, not weakness."],"focus":["impact","precision"]},
    {"id":"presence-doc-mid-04","level":"mid","profession":"doctor","title":"The recommendation to the tumor board","scenario":"At the multidisciplinary meeting, you've presented a complex case and now everyone's looking at you for direction. Your draft trails off into \"so those are the considerations.\" The room needs you to land a recommendation they can debate.","task":"Write the closing 2-3 sentences that state your recommended plan and invite challenge.","tips":["Land a plan: here's what I recommend and why.","Invite challenge explicitly — confidence isn't refusing input.","Trailing off into \"considerations\" leaves a vacuum someone else fills."],"focus":["impact","clarity"]},
    {"id":"presence-doc-mid-05","level":"mid","profession":"doctor","title":"The neutral menu to the CMO","scenario":"The CMO asked how your service should handle the coming merger of two units. Your instinct is to present it as balanced options so no one can fault you. But the CMO can read a pro/con list themselves — they want your read.","task":"Rewrite the response to lead with your recommendation and the single decisive reason.","tips":["Lead with what you'd do if it were your call — because effectively it is.","One decisive reason beats a balanced table.","Hedging to avoid blame also forfeits credit and trust."],"focus":["impact","clarity"]},
    {"id":"presence-doc-mid-06","level":"mid","profession":"doctor","title":"Standing behind the discharge decision","scenario":"A worried family pushes back on your decision to discharge their father, and your draft softens into \"well, we could keep him if you'd prefer.\" If discharge is right, wavering to please them isn't kindness — it's abdicating the judgment they're relying on.","task":"Write a 2-3 sentence response that owns the decision warmly but firmly.","tips":["State the decision and the clinical reason behind it.","Acknowledge the fear without surrendering the judgment.","Firm and warm are compatible; wavering is neither."],"focus":["impact","audience"]},
    {"id":"presence-doc-mid-07","level":"mid","profession":"doctor","title":"The recommendation in the budget meeting","scenario":"In the budget meeting, you're asked whether the unit needs the new monitors or can wait a year. Your draft presents utilization data and stops. The finance lead wants a clear ask backed by a clear reason, not raw numbers to interpret.","task":"Write the ask: your recommendation, the amount, and the one consequence of waiting.","tips":["Make the ask, don't just present the evidence for it.","One consequence of inaction the room can feel.","Numbers are your support; the recommendation is your job."],"focus":["impact","precision"],"placeholder":"I recommend approving the monitors this cycle — waiting a year means we keep borrowing from the ICU, which delayed six transfers last month."},
    {"id":"presence-doc-mid-08","level":"mid","profession":"doctor","title":"The confident \"here's what we'll do\"","scenario":"An unexpected staffing gap hits your unit mid-shift and the team looks to you. Your draft thinks aloud through the problem in front of them, which reads as uncertainty. Presence is converting your reasoning into a clear plan before you speak it.","task":"Write the 2-3 sentence plan you'd announce to the team, decisive and specific.","tips":["Announce the plan, then the reasoning — not the reverse.","Specific assignments beat a general call to pull together.","The team's calm is downstream of your visible clarity."],"focus":["impact","structure"]},
    {"id":"presence-doc-mid-09","level":"mid","profession":"doctor","title":"Separating what happened from what you fear","scenario":"You're briefing leadership on a bad outcome and your draft mixes established facts with your anxieties about liability and blame. The mix undermines you. Presence is stating what's known cleanly and flagging concerns as concerns.","task":"Rewrite the brief to give the known facts first, then flag your concerns separately.","tips":["Facts stand alone before any worry is voiced.","Label concerns as concerns: \"what I'm watching for is.\"","Leaders trust a briefer who separates evidence from anxiety."],"focus":["impact","precision"]},
    {"id":"presence-doc-mid-10","level":"mid","profession":"doctor","title":"The recommendation the resident needs","scenario":"A resident presents a case and asks what you'd do. Your draft walks through all the possibilities without landing, hoping they'll learn by watching you deliberate. But at this moment they need to see an attending commit to a plan.","task":"Write the 2-3 sentence answer that commits to a plan and names your reasoning.","tips":["Commit to a plan; then you can teach the reasoning behind it.","Modeling decisiveness is itself the lesson.","Deliberation is valuable; endless deliberation is a tell."],"focus":["impact","clarity"]},
    {"id":"presence-doc-mid-11","level":"mid","profession":"doctor","title":"Owning the QI proposal","scenario":"You're presenting a QI proposal to the committee and your draft frames it as \"one idea we might consider exploring.\" That triple-hedge invites the committee to shelve it. If you believe in the change, present it as a proposal you stand behind.","task":"Rewrite the framing to present the change as a recommendation you're asking them to approve.","tips":["Say \"I'm proposing,\" not \"we might consider exploring.\"","Ask for the decision you actually want: approval.","Tentative framing gives a committee permission to defer."],"focus":["impact","clarity"],"placeholder":"I'm proposing we adopt the discharge checklist unit-wide, and I'm asking the committee to approve it today."},
    {"id":"presence-doc-mid-12","level":"mid","profession":"doctor","title":"The signposted grand rounds","scenario":"You're opening grand rounds and your draft dives straight into content. A senior audience stays with you longer if you tell them the destination first. Presence at the podium is orienting the room before you fill it.","task":"Write the opening that states your one governing claim and the three points that will support it.","tips":["Give them the claim and the map in the first thirty seconds.","Three named points let the audience track your progress.","Orienting the room is what a confident speaker does first."],"focus":["impact","structure"]},
    {"id":"presence-doc-mid-13","level":"mid","profession":"doctor","title":"The recommendation under scrutiny","scenario":"The executive team is skeptical of your proposal to add a service line. Your draft, sensing resistance, retreats into \"of course, it's ultimately your decision.\" That surrender concedes the room. Presence is holding your recommendation while genuinely inviting the pushback.","task":"Write a 2-3 sentence response that restates your recommendation and invites the specific objection.","tips":["Restate the recommendation before addressing doubt.","Invite the real objection: \"what's the biggest concern?\"","Deferring to authority isn't humility when they asked for your view."],"focus":["impact","clarity"]},
    {"id":"presence-doc-mid-14","level":"mid","profession":"doctor","title":"The clear position on the ethics question","scenario":"In an ethics discussion about a difficult case, your draft catalogs every perspective and offers none of your own. As the attending, cataloging isn't leadership — the team needs to hear where you land and why, offered as a position open to challenge.","task":"Write a 2-3 sentence statement of your position and its ethical reasoning.","tips":["Take a position; the case still needs a decision.","Ground it in one clear principle, not a survey of all of them.","A position invites productive disagreement; a survey invites drift."],"focus":["impact","clarity"]},
    {"id":"presence-doc-mid-15","level":"mid","profession":"doctor","title":"The fact-first incident brief","scenario":"You're the first to brief the director after a serious safety event, and emotions on the unit are high. Your draft leads with reassurance and blame-deflection. Presence is leading with the established facts, calmly, and reserving judgment until it's earned.","task":"Write the opening two sentences: the established facts only, in a steady register.","tips":["Open with what is known, stated plainly and without spin.","Resist the urge to reassure or deflect in sentence one.","A steady factual opening projects control of the situation."],"focus":["impact","precision"],"placeholder":"At 14:20 a patient received a double dose of the intended medication; she is stable and being monitored."},
    {"id":"presence-doc-mid-16","level":"mid","profession":"doctor","title":"The recommendation to the nursing director","scenario":"The nursing director asks whether to change the shift-change time on your unit. Your draft offers a balanced analysis and no view. You've run this unit for three years — your reticence reads as indecision, not neutrality.","task":"Write a 2-3 sentence recommendation with the change you'd make and its main benefit.","tips":["Recommend the specific change and the time.","Name the one benefit that decides it for you.","Experience earns you the right to a view — use it."],"focus":["impact","clarity"]},
    {"id":"presence-doc-mid-17","level":"mid","profession":"doctor","title":"Holding the room in the difficult meeting","scenario":"A tense multidisciplinary meeting is fragmenting into side arguments. Your draft of the intervention is apologetic — \"sorry to interrupt.\" As chair, presence is naming the drift and re-anchoring to the decision without apologizing for doing your job.","task":"Write the 2 sentences you'd use to re-anchor the room to the decision at hand.","tips":["Name the drift and redirect: \"let's come back to the decision.\"","Skip the apology — steering the meeting is your role.","Restate the one question the meeting must answer."],"focus":["impact","structure"],"placeholder":"Let's pause the side discussion and come back to the one decision we're here for: rehab or home."},
    {"id":"presence-doc-mid-18","level":"mid","profession":"doctor","title":"The recommendation email that owns it","scenario":"You're emailing leadership about whether to keep a temporary process permanently. Your draft is a wall of considerations ending in \"happy to discuss.\" Presence in writing is stating your recommendation clearly enough that \"happy to discuss\" becomes optional.","task":"Rewrite the email's core to state your recommendation, one reason, and the decision you want.","tips":["The email should be able to stand without the meeting.","State the recommendation, the reason, the requested decision.","\"Happy to discuss\" should follow a position, not replace one."],"focus":["impact","concision"]},
    {"id":"presence-doc-mid-19","level":"mid","profession":"doctor","title":"The calm answer to the alarmed board","scenario":"A board member, alarmed by a headline, asks if your unit is safe. Your draft is defensive and detailed. Presence is answering the real question directly and calmly, then giving the one fact that supports the answer — not a flood.","task":"Write a 2-sentence answer: the direct answer, then the single supporting fact.","tips":["Answer the yes/no first, in a calm register.","One strong supporting fact, not a defensive dossier.","Calm brevity reassures a board more than volume."],"focus":["impact","audience"],"placeholder":"Yes, the unit is safe. Our infection and error rates are both below the national benchmark and trending down."},
    {"id":"presence-doc-mid-20","level":"mid","profession":"doctor","title":"The recommendation that names its own risk","scenario":"You're recommending an aggressive discharge target to leadership and your draft hides the risk to avoid weakening the pitch. But presence is naming the risk yourself — it shows you've thought it through and lets you frame it, rather than having it raised against you.","task":"Write the recommendation plus the one honest risk and how you'll manage it.","tips":["State the recommendation, then \"the risk is,\" then your mitigation.","Naming the risk first denies it to your critics.","Owning the downside is what separates a leader from a salesman."],"focus":["impact","precision"]},
    {"id":"presence-doc-mid-21","level":"mid","profession":"doctor","title":"The judgment call, clearly marked","scenario":"A colleague asks whether a borderline patient should go to the ICU. It's a judgment call with no clean answer. Your draft muddles fact and feel. Presence is stating the facts, then owning the judgment as yours, clearly.","task":"Write a 2-3 sentence answer separating the facts from your judgment call.","tips":["Lay out the facts both sides agree on.","Then own the call: \"my judgment is,\" and the reason.","A clearly-owned judgment is easier to trust than a hedge."],"focus":["impact","precision"]},
    {"id":"presence-doc-mid-22","level":"mid","profession":"doctor","title":"The confident close to the town hall","scenario":"You're closing a staff town hall after a hard month. Your draft peters out with logistics. The team needs you to close with a clear message about where things stand and where you're taking them — presence is ending on a point, not a reminder about parking.","task":"Write a 2-3 sentence closing that lands one clear message and a direction.","tips":["End on the message you want them to carry out the door.","One direction, stated with conviction, not a to-do list.","How you close is what they'll remember from the hour."],"focus":["impact","clarity"]},
    {"id":"presence-doc-mid-23","level":"mid","profession":"doctor","title":"The recommendation to escalate — or not","scenario":"A resident asks whether to escalate a deteriorating patient to the rapid-response team. Your draft lists considerations. In a time-pressured moment, considerations aren't leadership — they need a clear call and the trigger that would change it.","task":"Write a 2-sentence answer: your call, and the specific trigger that would change it.","tips":["Make the call now: escalate or watch.","Name the trigger that flips your answer.","A clear call with a trigger teaches better than a hedge."],"focus":["impact","clarity"],"placeholder":"Call the rapid-response team now. If you'd rather watch, then the moment her breathing rate crosses 30, you call — no waiting."},
    {"id":"presence-doc-mid-24","level":"mid","profession":"doctor","title":"Owning the schedule decision","scenario":"Two colleagues both want the same week off and it's your call. Your draft agonizes visibly and defers the decision. Presence is making the call, communicating it cleanly, and owning the reasoning — not distributing the discomfort by refusing to decide.","task":"Write a 2-3 sentence message that states your decision and the fair reason behind it.","tips":["Make the decision and state it plainly.","Give the reason so it reads as fair, not arbitrary.","Refusing to decide isn't neutral — it's a decision to let it fester."],"focus":["impact","clarity"]},
    {"id":"presence-doc-mid-25","level":"mid","profession":"doctor","title":"The recommendation that carries the room","scenario":"You have five minutes at the executive meeting to make the case for a change your unit needs. Your draft opens with context and never quite lands the ask. Presence in a short slot is opening with the recommendation and spending the rest earning it.","task":"Write the opening two sentences: the recommendation, then the single strongest reason.","tips":["Open with the ask — five minutes has no room to build.","Follow with your best reason, not your first.","In a short slot, the recommendation must arrive first or not at all."],"focus":["impact","structure"],"placeholder":"I'm asking the group to approve a dedicated discharge nurse for the unit. Here's the one number that makes the case —"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-doc-mid-01","level":"mid","profession":"doctor","title":"The family's blunt question","scenario":"In a family conference, a son cuts through your explanation and asks flatly: \"Is my mother going to die?\" Your draft answer detours into disease processes and statistics. He asked a direct question and deserves a direct answer before any context.","task":"Write a 2-3 sentence answer that responds to the actual question first, honestly.","tips":["Answer the question he asked before adding anything.","Honesty with a direct question builds more trust than a hedge.","Context follows the answer; it doesn't replace it."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-mid-02","level":"mid","profession":"doctor","title":"The CMO's pointed follow-up","scenario":"You've presented your unit's numbers and the CMO asks: \"So did the initiative work or not?\" Your draft answer explains methodology. They asked a yes/no and want it first — the qualifications can come after they have the answer.","task":"Write a 2-3 sentence answer leading with a clear yes, no, or partly, then the qualifier.","tips":["Lead with yes, no, or partly — the actual answer.","One honest qualifier, not a paragraph of them.","Answering the question asked is a form of respect."],"focus":["clarity","precision"],"placeholder":"Partly — readmissions dropped, but length of stay didn't move. Here's the one reason for the split —"},
    {"id":"pressure-doc-mid-03","level":"mid","profession":"doctor","title":"\"I don't know\" with a path","scenario":"At the tumor board a colleague asks a question about the case you genuinely can't answer yet — the pathology isn't back. Your draft improvises a guess to avoid looking uncertain. The stronger move is an honest \"I don't know\" paired with how you'll find out.","task":"Write a 2-sentence response that admits the gap and states how and when you'll close it.","tips":["Say you don't know — improvising a guess is the real risk.","Attach the path: what you'll do and by when.","\"I don't know, but here's how I'll find out\" is a position of strength."],"focus":["clarity","precision"],"placeholder":"I don't know yet — the pathology is pending. I'll have it by tomorrow's board and will bring the answer then."},
    {"id":"pressure-doc-mid-04","level":"mid","profession":"doctor","title":"Pushback from the specialist","scenario":"A specialist challenges your management plan in front of the team: \"Why didn't you just start treatment sooner?\" Your draft gets defensive. The stronger reply answers with the specific clinical reasoning, not with defensiveness or apology.","task":"Write a 2-3 sentence reply that answers with specifics, not defensiveness.","tips":["Answer with the actual reason, calmly and specifically.","Don't apologize for a defensible decision or escalate the tension.","Specifics end a challenge; defensiveness fuels it."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-mid-05","level":"mid","profession":"doctor","title":"The surveyor's curveball","scenario":"An accreditation surveyor asks a question you weren't prepped for: \"Show me how you'd know if this protocol was being skipped.\" Your draft stalls. The move under pressure is to answer the actual question with what you do know, concretely.","task":"Write a 2-3 sentence answer that addresses the specific question with a concrete mechanism.","tips":["Answer what was asked, not the question you rehearsed.","Give a concrete mechanism, even if partial.","Under scrutiny, a specific honest answer beats a polished evasion."],"focus":["clarity","structure"]},
    {"id":"pressure-doc-mid-06","level":"mid","profession":"doctor","title":"The angry family member interrupts","scenario":"Mid-explanation, a daughter interrupts: \"You people keep changing the story. Which is it?\" Your draft defends the team. The better response answers her real question — what's actually true now — before addressing the frustration.","task":"Write a 2-3 sentence response that answers her question directly and acknowledges the frustration.","tips":["Give the current, clear answer first.","Acknowledge the mixed messages honestly — don't defend.","Answering the question calms more than defending the team."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-mid-07","level":"mid","profession":"doctor","title":"The budget challenge","scenario":"In the budget meeting, finance pushes: \"Every unit says they're understaffed. Why is yours special?\" Your draft gets indignant. The answer under pressure is the one specific fact that distinguishes your case, delivered without heat.","task":"Write a 2-3 sentence answer that meets the challenge with a distinguishing specific.","tips":["Don't take the bait of the tone — answer the substance.","Give the one fact that separates your case from the chorus.","A specific, calm answer wins the room; indignation loses it."],"focus":["clarity","precision"],"placeholder":"Fair question. What's different for us is the acuity — our patient-to-nurse ratio is fine, but our patients need twice the interventions —"},
    {"id":"pressure-doc-mid-08","level":"mid","profession":"doctor","title":"The resident's hard question","scenario":"A resident asks, in front of the team, why you made a call that turned out wrong in hindsight. Your draft dodges. The teaching move is to answer honestly — what you knew then, why the call was reasonable, and what you'd change.","task":"Write a 2-3 sentence honest answer that models accountability without self-flagellation.","tips":["Answer honestly: here's what I knew and why I chose it.","Own what you'd change without collapsing into blame.","Modeling honest accountability is the lesson they'll remember."],"focus":["clarity","impact"]},
    {"id":"pressure-doc-mid-09","level":"mid","profession":"doctor","title":"The question you can't fully answer","scenario":"Leadership asks whether a rare complication on your unit was preventable. The honest answer is partial: some factors were, some weren't, and one is still under review. Your draft either overclaims or stonewalls. The move is a precise, bounded answer.","task":"Write a 2-3 sentence answer that states what you know, what you don't, and what's pending.","tips":["Separate the settled from the pending, clearly.","Don't overclaim prevention or stonewall the question.","Precision about the boundary of your knowledge builds trust."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-mid-10","level":"mid","profession":"doctor","title":"The reporter's leading question","scenario":"A cleared reporter asks, \"Isn't it true your ER is dangerously overcrowded?\" The framing is loaded. Your draft either accepts the frame or refuses to engage. The move is to answer the legitimate core question in your own accurate terms.","task":"Write a 2-3 sentence answer that reframes to the accurate reality without dodging.","tips":["Don't accept a loaded frame or refuse to answer.","Reframe to what's true: busy, yes; unsafe, no — here's how you know.","Answer the fair question inside the unfair one."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-mid-11","level":"mid","profession":"doctor","title":"The specialist who won't come","scenario":"You've paged a specialist for an urgent consult and they push back: \"This can wait until morning.\" You disagree. Under pressure your draft either caves or escalates emotionally. The move is to restate the specific clinical reason it can't wait.","task":"Write a 2-3 sentence response that holds the request with the deciding clinical fact.","tips":["Don't cave to seniority or escalate to a fight.","State the one fact that makes it urgent, specifically.","Hold your ground on evidence, not on volume."],"focus":["clarity","precision"],"placeholder":"I hear you, but her blood pressure is dropping despite fluids — that's why I can't wait until morning."},
    {"id":"pressure-doc-mid-12","level":"mid","profession":"doctor","title":"The committee's skeptical drill-down","scenario":"You present a proposal and a committee member drills: \"How do you know this will actually change behavior and not just add paperwork?\" It's a fair and hard question. Your draft deflects. The move is to answer the actual doubt with your best evidence or honest uncertainty.","task":"Write a 2-3 sentence answer that meets the specific doubt head-on.","tips":["Answer the doubt they raised, not an easier version.","If your evidence is thin, say so and name your safeguard.","Meeting the hardest question directly earns the room's trust."],"focus":["clarity","impact"]},
    {"id":"pressure-doc-mid-13","level":"mid","profession":"doctor","title":"The patient's \"why did this happen\"","scenario":"A patient who suffered a complication asks you directly why it happened. Your draft hedges to avoid liability. But the patient asked a real question, and a bounded, honest answer serves them better than a wall of caution.","task":"Write a 2-3 sentence answer that responds honestly within what's known, without speculation.","tips":["Answer within what's established; don't speculate to fill silence.","Honesty here is both ethical and, usually, protective.","Say what's still being looked at rather than guessing."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-mid-14","level":"mid","profession":"doctor","title":"The chief's \"why is your unit different\"","scenario":"The chief compares your unit's metric unfavorably to another's and asks why. Your draft lists excuses. The stronger move is to answer with the one real driver — including any you own — before any context.","task":"Write a 2-3 sentence answer that names the actual driver, owning your part.","tips":["Lead with the real reason, including your share of it.","Excuses signal deflection; a named driver signals command.","Owning your part first disarms the comparison."],"focus":["clarity","impact"]},
    {"id":"pressure-doc-mid-15","level":"mid","profession":"doctor","title":"The trap of the compound question","scenario":"In a review meeting someone asks a three-part question at once: was it preventable, who's responsible, and what have you changed? Your draft tangles all three. The move is to separate them and answer the one that matters most first.","task":"Write an answer that separates the parts and leads with the most important one.","tips":["Name that it's three questions, then take them in order.","Answer the one that matters most first — usually the fix.","Separating a compound question is itself a sign of composure."],"focus":["clarity","structure"]},
    {"id":"pressure-doc-mid-16","level":"mid","profession":"doctor","title":"The nurse manager's direct challenge","scenario":"In a joint meeting, the nurse manager says: \"Your residents keep ordering things at shift change and it's unsafe.\" It's pointed and partly fair. Your draft defends the residents. The move is to answer the safety concern directly before any defense.","task":"Write a 2-3 sentence response that takes the safety point seriously and answers with a concrete step.","tips":["Answer the safety concern first, without defending reflexively.","Concede what's fair; a concrete step beats a rebuttal.","Taking the point seriously is how you keep the alliance."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-mid-17","level":"mid","profession":"doctor","title":"When you're wrong in the meeting","scenario":"Mid-meeting, a colleague produces data showing your stated number was wrong. Your draft either doubles down or over-apologizes. The composed move is to acknowledge the correction cleanly and adjust your point without drama.","task":"Write a 2-sentence response that accepts the correction and restates your point on the true number.","tips":["Accept the correction in one clean sentence.","Don't double down or spiral into apology.","Adjusting gracefully protects your credibility more than being right did."],"focus":["clarity","impact"],"placeholder":"You're right, it's 11% not 16% — thank you. That actually strengthens the point, because even at 11% we're above target."},
    {"id":"pressure-doc-mid-18","level":"mid","profession":"doctor","title":"The question outside your lane","scenario":"In a leadership meeting you're asked a detailed finance question that's genuinely outside your expertise. Your draft bluffs. The move is a clean handoff: what you can speak to, and who owns the rest.","task":"Write a 2-sentence response that answers your part and routes the rest to the right owner.","tips":["Answer the piece you legitimately know.","Route the rest to the named owner, don't bluff it.","A confident handoff beats a shaky guess."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-mid-19","level":"mid","profession":"doctor","title":"The family's ultimatum","scenario":"A family issues an ultimatum in the conference: \"Either you transfer him to a bigger hospital or we're taking him ourselves.\" Your draft either capitulates or hardens. The move is to answer the underlying fear and address the actual request directly.","task":"Write a 2-3 sentence response that addresses the request head-on and the fear beneath it.","tips":["Address the actual request plainly — is transfer indicated or not.","Answer the fear driving the ultimatum, not just the words.","Neither caving nor hardening; a direct, honest response."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-mid-20","level":"mid","profession":"doctor","title":"The \"just give me a number\" pressure","scenario":"Leadership presses you for a firm date the unit will hit a target, and you genuinely can't commit to one honestly. Your draft either invents a date or refuses. The move is to give the most honest bounded answer plus what it depends on.","task":"Write a 2-3 sentence answer with a realistic bounded estimate and its key dependency.","tips":["Give a range, not a false-precision date.","State the one dependency that would move it.","An honest bounded answer beats a number you'll miss."],"focus":["clarity","precision"],"placeholder":"Realistically, six to eight weeks — but that assumes the second nurse starts on time. If that slips, so does this."},
    {"id":"pressure-doc-mid-21","level":"mid","profession":"doctor","title":"The resident's public disagreement","scenario":"A resident openly disagrees with your plan on rounds in front of the team and a patient. Your draft either shuts it down or relitigates everything on the spot. The move is to answer the substance briefly and route the full debate to the right setting.","task":"Write a 2-3 sentence response that engages the point respectfully and manages the setting.","tips":["Engage the substance in one line — don't shut a resident down.","Move the full debate off the bedside to protect the patient.","Handling it respectfully models how disagreement should work."],"focus":["clarity","audience"]},
    {"id":"pressure-doc-mid-22","level":"mid","profession":"doctor","title":"The gotcha at grand rounds","scenario":"During Q&A after your grand rounds talk, an audience member asks a pointed question clearly meant to expose a weakness in your data. Your draft gets defensive. The move is to answer the legitimate technical point calmly, conceding what's true.","task":"Write a 2-3 sentence answer that addresses the technical point and concedes any fair part.","tips":["Answer the real technical question inside the gotcha.","Concede the fair part; it disarms the attack.","Composure under a pointed question is what the room remembers."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-mid-23","level":"mid","profession":"doctor","title":"The blame-seeking debrief question","scenario":"In an incident debrief, a team member asks pointedly, \"So whose fault was it?\" Your draft either names someone or dodges entirely. The move is to answer the real underlying question — what failed — and redirect from person to system.","task":"Write a 2-3 sentence response that answers the substance and reframes from blame to cause.","tips":["Answer what actually failed, not who.","Reframe blame to system without dodging the question.","A calm redirect keeps the debrief safe and useful."],"focus":["clarity","structure"],"placeholder":"The real question is what failed, and I'll answer that: the handoff had no check for pending results. That's a system gap, not a person's mistake —"},
    {"id":"pressure-doc-mid-24","level":"mid","profession":"doctor","title":"The two-part trap from counsel","scenario":"Hospital counsel asks a two-part question where answering the first part carelessly implies something about the second. Your draft rushes both. The move is to answer precisely, part by part, exactly and no more.","task":"Write a response that answers each part precisely and separately, without volunteering more.","tips":["Take the parts one at a time, precisely.","Answer exactly what's asked; don't fill silence.","Precision protects everyone here — vagueness creates work."],"focus":["clarity","precision"]},
    {"id":"pressure-doc-mid-25","level":"mid","profession":"doctor","title":"The impossible-to-please stakeholder","scenario":"A department peer keeps moving the goalposts on your shared project and asks, \"Why isn't this done yet?\" Your draft gets exasperated. The move is to answer the actual status plainly and name the specific dependency that's outside your control.","task":"Write a 2-3 sentence answer that states the true status and the controlling constraint calmly.","tips":["State the real status without defensiveness.","Name the specific dependency, not a general complaint.","Calm specifics end a goalpost-mover; frustration feeds them."],"focus":["clarity","precision"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-doc-mid-01","level":"mid","profession":"doctor","title":"Before and after the discharge nurse","scenario":"You're pitching a dedicated discharge nurse to the executive team. Numbers alone haven't moved them. A before-and-after picture of a single patient's discharge day — chaotic now, smooth after — makes the change concrete in a way a spreadsheet can't.","task":"Write a 3-4 sentence before/after: the discharge day as it is now, and as it would be with the role.","tips":["Paint the current state concretely — the delays, the scramble.","Then the after: the same day, transformed by the change.","A vivid before/after does what a statistic can't."],"focus":["impact","structure"]},
    {"id":"narrative-doc-mid-02","level":"mid","profession":"doctor","title":"Making the readmission stakes concrete","scenario":"Your readmission rate is an abstraction to the committee — 16% is just a number. You want them to feel the stakes. One anonymized story of a patient who bounced back because a follow-up wasn't booked makes 16% mean something.","task":"Write a 3-4 sentence account that turns the statistic into one concrete human consequence.","tips":["Anchor the number in one real (anonymized) patient's experience.","Concrete stakes move committees that abstract rates don't.","One story, honestly told, carries the whole number."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-03","level":"mid","profession":"doctor","title":"Pre-empting the cost objection","scenario":"You're proposing a new screening protocol and you know the first objection will be cost. Your draft ignores it and hopes. The persuasive move is to name the cost objection yourself and answer it before it's raised.","task":"Write a 2-3 sentence passage that raises the cost objection and answers it head-on.","tips":["Name the objection before your opponent does.","Answer it with the offsetting benefit or saving.","Pre-empting the strongest objection disarms the room."],"focus":["impact","precision"],"placeholder":"You'll ask what this costs — about $8,000 a year. Here's why it saves more than that —"},
    {"id":"narrative-doc-mid-04","level":"mid","profession":"doctor","title":"The change story for the team","scenario":"You're introducing a new workflow to a tired team that's seen changes fail before. A dry announcement won't land. You need a short narrative: here's the problem we all feel, here's what changes, here's the better day it creates.","task":"Write a 3-4 sentence change narrative moving from shared problem to better future.","tips":["Start from the pain they already feel — earn the setup.","Show the specific change, then the better day it produces.","A story of change beats a memo announcing one."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-05","level":"mid","profession":"doctor","title":"Persuading the skeptical specialist","scenario":"You want a specialist service to adopt your unit's earlier-referral pathway, and they're skeptical it's worth their disruption. The persuasive frame isn't your convenience — it's the better outcomes and fewer emergencies for their patients.","task":"Write a 2-3 sentence pitch framed entirely around their patients' outcomes.","tips":["Frame the benefit in their terms, not yours.","Make the outcome for their patients concrete.","Persuasion is showing them their own stake, not asserting yours."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-06","level":"mid","profession":"doctor","title":"The QI project's origin story","scenario":"You're presenting the results of your infection-reduction project and leading with methodology. It's forgettable. The memorable frame opens with the moment that started it — the near-miss that made the problem impossible to ignore.","task":"Write the 2-3 sentence opening that starts with the triggering moment, not the methods.","tips":["Open on the moment the problem became undeniable.","A concrete origin makes the whole project stick.","Methods are evidence; the story is what's remembered."],"focus":["impact","structure"],"placeholder":"This started the night we nearly lost a patient to an infection we should have prevented —"},
    {"id":"narrative-doc-mid-07","level":"mid","profession":"doctor","title":"Pre-empting the \"we tried that\" objection","scenario":"You're proposing a checklist and you know a senior colleague will say \"we tried checklists years ago and they didn't stick.\" Your draft avoids the history. The stronger move is to name that failure and show what's different this time.","task":"Write a 2-3 sentence passage that acknowledges the past failure and shows what changed.","tips":["Name the prior failure honestly — don't pretend it didn't happen.","Show the specific difference that makes this attempt work.","Owning the history is more persuasive than ignoring it."],"focus":["impact","precision"]},
    {"id":"narrative-doc-mid-08","level":"mid","profession":"doctor","title":"The donor pitch that shows the gap","scenario":"You're asking a foundation to fund a patient-navigation program. Your draft lists what the money buys. The persuasive frame shows the gap it fills — the patient who falls through the cracks now, and the different ending the program creates.","task":"Write a 3-4 sentence pitch contrasting the patient's journey now versus with the program.","tips":["Show the gap through one patient's path, not a feature list.","Contrast the current ending with the funded one.","Donors give to close a gap they can see."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-09","level":"mid","profession":"doctor","title":"Framing the staffing case with stakes","scenario":"You've asked for more nursing coverage with pure ratios and been declined. This time you'll lead with the stake: what a thin night shift means when a patient deteriorates and there's no one to notice in time.","task":"Write a 2-3 sentence framing that makes the human stake of the staffing gap concrete.","tips":["Make the consequence of inaction vivid and specific.","One realistic scenario beats another ratio table.","Stakes that people can picture move budgets."],"focus":["impact","structure"]},
    {"id":"narrative-doc-mid-10","level":"mid","profession":"doctor","title":"The strongest objection, answered first","scenario":"You're proposing to move routine follow-ups to telehealth and the strongest objection is that you'll miss physical findings. Rather than bury it, you'll open by naming it and showing your safeguard.","task":"Write a 2-3 sentence opening that raises the missed-findings objection and answers it.","tips":["Lead by naming the objection your opponents respect most.","Show your specific safeguard against it.","Answering the strongest objection first wins the credibility for the rest."],"focus":["impact","precision"],"placeholder":"The real risk with telehealth is missing something you'd only catch in person. Here's exactly how we screen for that —"},
    {"id":"narrative-doc-mid-11","level":"mid","profession":"doctor","title":"The resident's growth arc","scenario":"You're writing a recommendation and want to persuade the committee this resident is exceptional. A list of accomplishments is flat. An arc — where she started, the turning point, where she is now — is persuasive because it shows trajectory, not just a snapshot.","task":"Write a 3-4 sentence narrative arc: starting point, turning moment, current standing.","tips":["Show growth, not a static list of strengths.","Anchor the turning point in one specific moment.","An arc persuades because it predicts future trajectory."],"focus":["impact","structure"]},
    {"id":"narrative-doc-mid-12","level":"mid","profession":"doctor","title":"Selling the protocol with one patient","scenario":"You're rolling out a sepsis protocol and the abstract case for it hasn't landed with the ward. You'll open the rollout meeting with one patient whose outcome would have been different with the protocol — making the benefit unforgettable.","task":"Write a 3-4 sentence opening built around that single illustrative patient.","tips":["One patient's story makes the protocol's value concrete.","Show what the protocol would have changed for them.","The ward remembers a patient; they forget a guideline."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-13","level":"mid","profession":"doctor","title":"The before/after for the new equipment","scenario":"You want funding for a bedside ultrasound. Your draft cites capabilities. The persuasive frame contrasts a specific delayed diagnosis under the current setup with the same case caught in minutes with the device.","task":"Write a 3-4 sentence before/after built around one diagnostic scenario.","tips":["Contrast the same case with and without the equipment.","Make the time saved a clinical consequence, not a convenience.","Before/after turns a spec sheet into a decision."],"focus":["impact","structure"]},
    {"id":"narrative-doc-mid-14","level":"mid","profession":"doctor","title":"Pre-empting the workload objection","scenario":"You're pitching a new documentation standard and the team's objection will be added workload. Your draft glosses over it. The persuasive move is to name the extra minutes honestly and show what they buy back downstream.","task":"Write a 2-3 sentence passage that concedes the added workload and shows the net gain.","tips":["Admit the cost — the team already knows it's there.","Show the downstream time it saves, concretely.","Honesty about the cost makes the benefit believable."],"focus":["impact","precision"],"placeholder":"Yes, this adds about two minutes per note. It also saves the twenty minutes you spend reconstructing the story every readmission —"},
    {"id":"narrative-doc-mid-15","level":"mid","profession":"doctor","title":"The community talk that persuades","scenario":"You're speaking to a community group about a preventive screening most of them avoid. Statistics on risk haven't worked before. A story — someone whose life a screening changed, told with care — persuades where the odds don't.","task":"Write a 3-4 sentence story that makes the case for screening through one honest human example.","tips":["Lead with a person, not a percentage.","Keep it honest — no fear-mongering, just a true arc.","A story earns the attention a statistic can't."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-16","level":"mid","profession":"doctor","title":"The case for the schedule change","scenario":"You want to change the clinic's appointment structure and staff are attached to the current one. Your draft argues efficiency. The persuasive frame shows the frustrating current experience — for both patients and staff — and the better one the change creates.","task":"Write a 3-4 sentence before/after covering both the patient and staff experience.","tips":["Show the current frustration both sides live with.","Then the shared better day the change produces.","Persuasion includes the people whose habits you're changing."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-17","level":"mid","profession":"doctor","title":"The strongest objection to the merger","scenario":"You're advocating for merging two clinic services and the strongest objection is loss of specialized care. You'll open by naming it and showing how the merged model actually protects specialization better than the status quo.","task":"Write a 2-3 sentence passage that raises the specialization fear and reframes it.","tips":["Name the fear that carries the most weight.","Show how your proposal answers rather than dismisses it.","Reframing the strongest objection is more persuasive than avoiding it."],"focus":["impact","precision"]},
    {"id":"narrative-doc-mid-18","level":"mid","profession":"doctor","title":"The safety story for the board","scenario":"You're presenting the year's safety work to the board and the numbers are good but dry. One narrative — a near-miss that your new system caught — shows the board what their investment prevented, in human terms.","task":"Write a 3-4 sentence account of a near-miss the system caught, and what it prevented.","tips":["Show the system working in one concrete instance.","Make the averted harm tangible to a non-clinical board.","A caught near-miss is proof the investment paid off."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-19","level":"mid","profession":"doctor","title":"Persuading a colleague to change practice","scenario":"A respected colleague still uses an outdated approach and you want them to change without a confrontation. A lecture won't work. The persuasive move is a story: a case where the newer approach clearly served the patient better, offered peer to peer.","task":"Write a 2-3 sentence peer-to-peer framing that persuades through a shared case, not a lecture.","tips":["Frame it as sharing, not correcting.","Let the case make the argument for you.","Peers change practice for stories, rarely for citations."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-20","level":"mid","profession":"doctor","title":"The vision for the unit","scenario":"You're rallying the team behind a year-long improvement effort and your draft is a project plan. Plans don't inspire. You need a short vision of what the unit feels like when it works — the future state worth the effort.","task":"Write a 3-4 sentence vision of the improved unit that makes the effort feel worthwhile.","tips":["Paint the destination, not just the route.","Make the future state concrete and desirable.","A vision motivates the work a plan only organizes."],"focus":["impact","structure"]},
    {"id":"narrative-doc-mid-21","level":"mid","profession":"doctor","title":"Pre-empting the \"it won't scale\" objection","scenario":"Your pilot succeeded on one ward and you're asking to scale it hospital-wide. The obvious objection: what works on one motivated ward won't scale. Your draft ignores it. The move is to name it and show why this scales.","task":"Write a 2-3 sentence passage that raises the scaling doubt and answers it specifically.","tips":["Name the scaling objection — it's the first thing they'll think.","Show the specific reason this one travels.","Addressing the doubt is what earns the expansion."],"focus":["impact","precision"]},
    {"id":"narrative-doc-mid-22","level":"mid","profession":"doctor","title":"The human cost of the wait","scenario":"You're arguing to expand clinic hours to cut the waitlist. The waitlist is a number to leadership. You'll make it a person: what a six-month wait means for one patient whose condition worsened while they waited.","task":"Write a 3-4 sentence account making the waitlist's human cost concrete.","tips":["Turn the queue length into one patient's deterioration.","Keep it honest and specific, not manipulative.","The number opens the door; the story walks through it."],"focus":["impact","audience"]},
    {"id":"narrative-doc-mid-23","level":"mid","profession":"doctor","title":"The turnaround narrative","scenario":"Your unit had a rough year and you're presenting the recovery to leadership. A list of fixes is flat. A turnaround narrative — how bad it got, what you changed, where you are now — is persuasive and rebuilds confidence in your leadership.","task":"Write a 3-4 sentence turnaround arc: the low point, the intervention, the current state.","tips":["Be honest about the low point — it earns the recovery.","Show the specific change that turned it.","A credible turnaround story restores trust a metric can't."],"focus":["impact","structure"]},
    {"id":"narrative-doc-mid-24","level":"mid","profession":"doctor","title":"Framing the ask to the reluctant chief","scenario":"Your chief is reluctant to approve a new role and you have one conversation. A demand won't work. The persuasive frame connects your ask to something the chief already cares about — a metric they're accountable for that your role directly improves.","task":"Write a 2-3 sentence ask that ties your request to the chief's own priority.","tips":["Connect your ask to what the chief is already accountable for.","Show your request as a solution to their problem, not yours.","Persuasion aligns your want with their need."],"focus":["impact","audience"],"placeholder":"You've been under pressure on length of stay — this discharge role is the fastest lever we have on exactly that number —"},
    {"id":"narrative-doc-mid-25","level":"mid","profession":"doctor","title":"The full persuasive case, compact","scenario":"You have three minutes to persuade the executive committee to fund your proposal. You need the whole arc compressed: the problem's stakes, the change, the strongest objection answered, and the ask — all in a tight package.","task":"Write a 4-5 sentence persuasive case: stakes, change, pre-empted objection, ask.","tips":["Compress the full arc — every sentence earns its place.","Stakes and objection are what make the ask land.","In three minutes, structure is the persuasion."],"focus":["impact","structure"],"placeholder":"Right now, one in six of our patients comes back within a month — here's what that costs and how we fix it —"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-doc-mid-01","level":"mid","profession":"doctor","title":"Front-loading bad news to the family","scenario":"You're meeting a family to tell them their father's cancer has spread and treatment intent has shifted from cure to comfort. Your draft delays the news through several minutes of test recap. Clear is kind: they deserve the headline before the details, gently but without a maze first.","task":"Write the first 2-3 sentences of the conversation, leading with the news compassionately.","tips":["Lead with the news, warmly — don't make them wait through a recap.","One clear sentence, then a pause for it to land.","Delaying bad news to soften it usually makes it harder."],"focus":["clarity","audience"],"placeholder":"I have difficult news, and I want to tell you clearly: the cancer has spread, and we can no longer aim to cure it —"},
    {"id":"hard-doc-mid-02","level":"mid","profession":"doctor","title":"The clean no to the resident","scenario":"A resident asks to swap onto a lighter rotation and the answer is no — the service can't spare them. Your draft cushions the no so heavily it sounds like a maybe. A clean no, kindly delivered, respects them more than a soft one that breeds false hope.","task":"Write a 2-3 sentence response that says no clearly and explains briefly.","tips":["Say no in the first sentence — don't bury it in cushioning.","One honest reason, not a wall of justification.","A clear no is kinder than a soft maybe."],"focus":["clarity","impact"]},
    {"id":"hard-doc-mid-03","level":"mid","profession":"doctor","title":"Behavior, impact, ask with a resident","scenario":"A resident has been dismissive of nursing staff and it's affecting the team. You need to give feedback that changes the behavior. The structure that works: name the specific behavior, its impact, then the ask — without character judgment.","task":"Write 3-4 sentences using behavior, then impact, then a clear ask.","tips":["Name the specific behavior, not a character trait.","State the concrete impact on the team and patients.","End with a clear, doable ask — not a vague 'do better'."],"focus":["clarity","structure"],"placeholder":"On rounds yesterday you overrode the nurse's concern without hearing it out. The effect is that nurses stop flagging problems early —"},
    {"id":"hard-doc-mid-04","level":"mid","profession":"doctor","title":"Telling the surgeon the case is off","scenario":"You must tell a surgeon their patient isn't fit for tomorrow's elective procedure — a decision they'll dislike. Your draft over-apologizes and hedges. Clear is kind here too: state the decision and the clinical reason plainly, then discuss.","task":"Write the 2-3 sentence message: the decision, the reason, delivered without hedging.","tips":["State the decision first, clearly, then the clinical basis.","Skip the over-apology — this is sound judgment, not a failure.","Clarity respects the surgeon's need to replan."],"focus":["clarity","precision"]},
    {"id":"hard-doc-mid-05","level":"mid","profession":"doctor","title":"The disclosure of a medical error","scenario":"A patient received the wrong medication dose due to a system error. Hospital policy and ethics require disclosure. Your draft buries the fact in vague language. Honest disclosure front-loads what happened, plainly, before any explanation.","task":"Write the opening 2-3 sentences of the disclosure, stating clearly what happened.","tips":["State plainly what happened — vagueness reads as evasion.","Lead with the fact, then what you're doing about it.","Honest, direct disclosure is both right and protective."],"focus":["clarity","precision"],"placeholder":"I need to tell you about a mistake in your care. Yesterday you received twice the intended dose of a medication —"},
    {"id":"hard-doc-mid-06","level":"mid","profession":"doctor","title":"The performance conversation","scenario":"A long-serving nurse's practice has slipped and you must address it. Your draft is so gentle the message disappears. Clear is kind: they can't fix what they can't hear. Front-load the concern with specifics, then support.","task":"Write the 2-3 sentence opening that states the concern specifically and offers support.","tips":["Name the specific concern in the first sentence.","Follow with genuine support, not a threat.","A clear concern respected them enough to be honest."],"focus":["clarity","audience"]},
    {"id":"hard-doc-mid-07","level":"mid","profession":"doctor","title":"Declining the extra committee role","scenario":"A senior colleague asks you to chair another committee and you must decline — you're overextended. Your draft rambles apologetically toward a soft no. A clean no with a genuine reason, and no false 'maybe later,' is the honest answer.","task":"Write a 2-3 sentence decline that is clear, honest, and free of false openings.","tips":["Say no clearly; don't leave a door you'll have to close later.","Give one honest reason without over-explaining.","Respect them with a real answer, not a polite deferral."],"focus":["clarity","concision"],"placeholder":"I have to say no to chairing this — I'm already at capacity and wouldn't do it justice. I want to be straight with you rather than half-commit."},
    {"id":"hard-doc-mid-08","level":"mid","profession":"doctor","title":"The prognosis a patient must hear","scenario":"A patient asks directly how long they have, and the honest answer is short. Your draft retreats into statistics and vagueness to avoid the moment. Clear is kind: an honest, gentle range, then presence — not a fog of numbers.","task":"Write the 2-3 sentences that give an honest answer with compassion.","tips":["Answer honestly — evasion here is a kind of abandonment.","Give a gentle, real range, then stop and be present.","Compassion is telling the truth, then staying in the room."],"focus":["clarity","audience"]},
    {"id":"hard-doc-mid-09","level":"mid","profession":"doctor","title":"The feedback the fellow won't like","scenario":"A fellow you're mentoring has a blind spot that's holding them back, and they've resisted feedback before. You need to deliver it so it lands. Behavior, impact, ask — anchored in specifics they can't dismiss as personality.","task":"Write a 3-4 sentence feedback using behavior, impact, and a specific ask.","tips":["Ground it in one specific, undeniable instance.","Impact makes it real; the ask makes it fixable.","Specifics survive the defensiveness a trait-label triggers."],"focus":["clarity","structure"]},
    {"id":"hard-doc-mid-10","level":"mid","profession":"doctor","title":"Telling the team about the budget cut","scenario":"Leadership cut your unit's budget and a planned hire is off. You must tell the team, who were counting on the relief. Your draft opens with a long defense of leadership. Clear is kind: front-load the news, then the honest context.","task":"Write the 2-3 sentence opening that delivers the news, then gives honest context.","tips":["Lead with the news — the team will brace either way.","Don't spend the opening defending the decision-makers.","Honest context after the news reads better than a preamble before it."],"focus":["clarity","audience"],"placeholder":"I have news I know you were hoping not to hear: the additional nurse position is on hold this year —"},
    {"id":"hard-doc-mid-11","level":"mid","profession":"doctor","title":"The 'no' to a demanding family request","scenario":"A family demands a treatment that isn't medically appropriate and won't help their relative. You must decline. Your draft either caves toward vagueness or sounds cold. A clear, compassionate no explains the why and holds the line.","task":"Write a 2-3 sentence response that declines clearly and compassionately, with the reason.","tips":["Say no clearly, then the reason it wouldn't help.","Acknowledge the love behind the request.","A clear no with a reason is kinder than false hope."],"focus":["clarity","audience"]},
    {"id":"hard-doc-mid-12","level":"mid","profession":"doctor","title":"The escalation about a colleague","scenario":"You must raise concerns about a peer's conduct to the department chief — a hard message about someone you work alongside. Your draft is so hedged the concern is invisible. State the specific concern and its impact clearly; the chief needs facts, not hints.","task":"Write a 2-3 sentence escalation that states the specific concern and its impact plainly.","tips":["State the concern with specifics, not insinuation.","Focus on impact — patients, team — not personality.","Hedging a serious concern fails the people it's meant to protect."],"focus":["clarity","precision"]},
    {"id":"hard-doc-mid-13","level":"mid","profession":"doctor","title":"The redirection at the family meeting","scenario":"A family is fixated on a treatment path that's no longer realistic and you must redirect toward comfort-focused goals. Your draft dances around it for fear of taking away hope. Clear is kind: name the reality gently, then offer the path forward.","task":"Write the 2-3 sentence redirection that names the reality and offers a way forward.","tips":["Name where things really stand, gently but plainly.","Offer the next path so it's redirection, not abandonment.","Removing false hope is what makes room for real support."],"focus":["clarity","audience"]},
    {"id":"hard-doc-mid-14","level":"mid","profession":"doctor","title":"The apology for the system failure","scenario":"A patient waited hours in pain because of a scheduling breakdown on your unit. You owe an apology that's genuine, not defensive. Front-load a clear apology and ownership, then the fix — no explaining-away in the first breath.","task":"Write a 2-3 sentence apology that owns the failure clearly, then states the fix.","tips":["Apologize plainly and own it — no 'but' in the first sentence.","One genuine apology, then the concrete fix.","Ownership repairs trust; explaining-away spends it."],"focus":["clarity","impact"],"placeholder":"You waited three hours in pain and that shouldn't have happened. I'm sorry — that's on us, and here's what we're changing —"},
    {"id":"hard-doc-mid-15","level":"mid","profession":"doctor","title":"The 'you're not ready' message","scenario":"A resident wants to run a complex case independently and isn't ready. You must tell them without crushing them. Behavior-impact-ask, framed as a not-yet with a path, delivers the hard truth while keeping them motivated.","task":"Write a 3-4 sentence message that says not-yet clearly and gives a concrete path to ready.","tips":["Be clear it's not yet — don't let them mishear a soft no as yes.","Name the specific gap and the path to close it.","A path forward turns a hard no into a goal."],"focus":["clarity","structure"]},
    {"id":"hard-doc-mid-16","level":"mid","profession":"doctor","title":"Telling nursing the protocol is changing back","scenario":"A protocol you championed isn't working and you're reverting it — an admission the nurses will notice. Your draft hides the reversal in bureaucratic language. Clear is kind: name the change, own that the last one didn't work, keep it simple.","task":"Write a 2-3 sentence message that states the reversal plainly and owns it.","tips":["Name the change and that the prior one didn't pan out.","Owning the miss builds more credibility than spinning it.","Nurses respect a leader who says plainly what changed."],"focus":["clarity","impact"]},
    {"id":"hard-doc-mid-17","level":"mid","profession":"doctor","title":"The difficult truth to the optimistic patient","scenario":"A patient is convinced they're improving when the scans show otherwise. You must correct the misunderstanding compassionately. Your draft avoids contradicting them directly. Clear is kind: name the reality gently but unmistakably, then support.","task":"Write a 2-3 sentence response that corrects the misunderstanding gently and clearly.","tips":["Don't let a comfortable misunderstanding stand — correct it kindly.","Be unmistakable about the reality while staying warm.","Then be present; clarity earns the right to comfort."],"focus":["clarity","audience"]},
    {"id":"hard-doc-mid-18","level":"mid","profession":"doctor","title":"The feedback to a peer, not a junior","scenario":"A physician colleague's discharge summaries are consistently incomplete and it's causing follow-up failures. Giving feedback to a peer is harder than to a junior. Behavior, impact, ask — respectful and specific, without the power gradient to lean on.","task":"Write a 2-3 sentence peer feedback using behavior, impact, and ask.","tips":["Ground it in the specific behavior and its downstream effect.","Peer feedback needs extra specificity and zero condescension.","A concrete ask is easier to accept than a general complaint."],"focus":["clarity","structure"],"placeholder":"A few of the discharge summaries have been missing the follow-up plan, and a couple of patients slipped through as a result —"},
    {"id":"hard-doc-mid-19","level":"mid","profession":"doctor","title":"The hard call on the schedule dispute","scenario":"Two team members are in conflict over call coverage and you've decided in a way one won't like. You must deliver the decision to the losing party. Your draft over-explains to soften it. State the decision clearly, the reason, and acknowledge the disappointment.","task":"Write a 2-3 sentence message stating the decision plainly and acknowledging the impact.","tips":["State the decision clearly — don't bury it in reasoning.","Give the reason once, then acknowledge the disappointment.","Clarity here prevents the decision from being relitigated."],"focus":["clarity","impact"]},
    {"id":"hard-doc-mid-20","level":"mid","profession":"doctor","title":"Disclosing the delayed diagnosis","scenario":"A review found that a patient's diagnosis was delayed by a missed result, and you must disclose it to them. Your draft minimizes. Ethical disclosure front-loads what happened clearly, without minimizing, then addresses what it means and what's being done.","task":"Write the 2-3 sentence opening of the disclosure, clear and non-minimizing.","tips":["State the delay plainly — don't soften it into nothing.","Follow with what it means for them and the fix.","Non-minimizing honesty is what disclosure requires."],"focus":["clarity","precision"]},
    {"id":"hard-doc-mid-21","level":"mid","profession":"doctor","title":"Telling a student they failed the rotation","scenario":"A student didn't meet the bar this rotation and you must tell them. Your draft is so cushioned the failing message doesn't come through. Clear is kind: they need to hear it unambiguously, with the specifics, and a path if one exists.","task":"Write a 2-3 sentence message that delivers the failing outcome clearly and specifically.","tips":["Be unambiguous that they didn't pass — no soft-focus.","Give the specific gaps, not a vague 'not quite there.'","Clarity, even here, is the respectful choice."],"focus":["clarity","structure"]},
    {"id":"hard-doc-mid-22","level":"mid","profession":"doctor","title":"The no to leadership","scenario":"Leadership asks your unit to take on a new service you genuinely can't absorb safely. You must decline upward. Your draft caves toward a reluctant yes. A clear, reasoned no to leadership — with the safety basis — is the responsible answer.","task":"Write a 2-3 sentence upward no that is clear, reasoned, and safety-grounded.","tips":["Say no clearly even upward — a reluctant yes is worse.","Ground it in the safety limit, specifically.","Offer the condition under which yes becomes possible."],"focus":["clarity","precision"],"placeholder":"I can't take this on safely as things stand — we'd be exceeding safe staffing ratios. If we get one more nurse, that changes —"},
    {"id":"hard-doc-mid-23","level":"mid","profession":"doctor","title":"The condolence with the hard honesty","scenario":"You're speaking with a family after a death where care was appropriate but the family is looking for someone to blame. You must be compassionate and also honest about what happened. Front-load genuine condolence, then honest clarity — not defensiveness.","task":"Write the 2-3 sentence opening that offers condolence and honest clarity together.","tips":["Lead with genuine condolence, fully, before anything else.","Then be honestly clear — don't slide into defending.","Compassion and honesty coexist; defensiveness kills both."],"focus":["clarity","audience"]},
    {"id":"hard-doc-mid-24","level":"mid","profession":"doctor","title":"The hard message about your own mistake","scenario":"You made a judgment error that affected a patient's care and you must tell your chief before they hear it elsewhere. Your draft minimizes your role. Front-load what you did, own it clearly, then what you've learned and changed — no burying the lede.","task":"Write a 2-3 sentence message that owns the mistake clearly to your chief.","tips":["State plainly what you did — self-report beats being found out.","Own it without excessive self-flagellation.","Then the correction: what you've changed as a result."],"focus":["clarity","impact"],"placeholder":"I want to flag a mistake I made before you hear it elsewhere. I misread a result and delayed a change in care by a day —"},
    {"id":"hard-doc-mid-25","level":"mid","profession":"doctor","title":"The goals-of-care pivot","scenario":"After weeks of aggressive treatment, you must lead a family conference pivoting toward comfort care for a patient who isn't recovering. This is among the hardest conversations. Clear is kind: name the reality, then the recommendation, with warmth and no maze.","task":"Write the 3-4 sentence core: the reality, your recommendation, delivered compassionately.","tips":["Name the reality gently but without a long lead-up.","Make a recommendation — don't hand them an impossible menu.","Warmth and clarity together are what this moment needs."],"focus":["clarity","audience"],"placeholder":"I wish I had better news. Despite everything we've tried, he isn't getting better, and I don't believe more aggressive treatment will change that —"}
  ],
  "putting-it-together": [
    {"id":"together-doc-mid-01","level":"mid","profession":"doctor","title":"The one-page proposal, whole","scenario":"You have one page to propose a discharge coordinator to the executive team — the lead, the structure, the evidence, the ask, all in a register a busy executive respects. This is everything at once, under a real length constraint.","task":"Write the full one-page proposal's opening paragraph: lead with the ask, then the strongest supporting point.","tips":["Lead with the ask and the number that justifies it.","Structure the page so a skimmer gets it from the first lines.","Match the register to executives: crisp, quantified, decisive."],"focus":["structure","impact"],"placeholder":"I'm requesting one discharge coordinator for the unit; it would free an estimated 300 bed-days a year at a cost the position pays back in four months —"},
    {"id":"together-doc-mid-02","level":"mid","profession":"doctor","title":"The family conference, start to finish","scenario":"You're leading a full family conference: bad news to deliver, a decision to reach, four family members with different needs. You must lead with the headline, structure the discussion, deliver the hard message clearly, and read the room throughout.","task":"Write the opening 3-4 sentences that lead with the message, signpost the structure, and set a compassionate tone.","tips":["Headline the message, then map what you'll cover.","Set a tone that lets a tense room settle.","Everything you've practiced converges in the first minute here."],"focus":["structure","audience"]},
    {"id":"together-doc-mid-03","level":"mid","profession":"doctor","title":"The same message, three channels","scenario":"A protocol change needs communicating three ways: a terse pager alert to on-call staff, a detailed email to the full team, and a one-line note for the whiteboard. Same content, three registers — matching the channel is the whole skill.","task":"Write all three versions of 'the sepsis screen moves to triage Monday': pager, email opener, whiteboard.","tips":["The pager gets the bare action; the email gets the why; the board gets the reminder.","Match length and register to each channel's constraints.","One message, three shapes — that's channel discipline."],"focus":["concision","audience"],"placeholder":"Pager: Sepsis screen moves to triage Mon. Email: Starting Monday, every admission gets the sepsis screen at triage — here's the why and the how. Board: Sepsis screen @ triage — starts Mon."},
    {"id":"together-doc-mid-04","level":"mid","profession":"doctor","title":"Editing the resident's memo like a reader","scenario":"A resident hands you a rambling memo to the safety committee to review before it goes up. Your job is to edit it as the committee will read it — cutting, restructuring, sharpening the ask — and teach by showing.","task":"Write the 2-3 sentence rewrite of their buried opening so the ask and evidence lead.","tips":["Read as the committee will: what's the ask, where's the proof.","Cut the throat-clearing; lead with the recommendation.","Edit to the reader's needs, not the writer's order of thought."],"focus":["structure","concision"]},
    {"id":"together-doc-mid-05","level":"mid","profession":"doctor","title":"The board presentation under time pressure","scenario":"Your ten-minute board slot got cut to four. You must compress the whole story — quality results, the one risk, the ask — into a quarter of the time, keeping the lead and the ask intact. Editing under constraint is the test.","task":"Write the 3-4 sentence compressed version that keeps the headline result, the risk, and the ask.","tips":["Cut to the three things that survive at four minutes.","Keep the lead and the ask; sacrifice the supporting detail.","Compression is editing everything you've learned at once."],"focus":["concision","impact"]},
    {"id":"together-doc-mid-06","level":"mid","profession":"doctor","title":"The escalation email that does everything","scenario":"You're escalating a persistent staffing shortage to leadership: it must lead with the ask, structure the evidence, be precise with numbers, own a recommendation, and pre-empt the budget objection — all in a few tight paragraphs.","task":"Write the email's first two sentences integrating the ask, a precise number, and the pre-empted objection.","tips":["Lead with the ask and the one hard number behind it.","Name the cost objection and answer it in the same breath.","Every skill shows up in a good escalation email."],"focus":["structure","precision"],"placeholder":"I'm requesting one additional night nurse; missed medication windows tripled last month under our current 1-to-8 ratio, and the position costs less than one avoidable adverse event —"},
    {"id":"together-doc-mid-07","level":"mid","profession":"doctor","title":"The rounds that model everything","scenario":"You're leading rounds and using the sickest patient to model the whole toolkit for residents: lead with the plan, structure tightly, be precise, and own the decision. Teaching by example means every principle is visible in ninety seconds.","task":"Write the 3-4 sentence model presentation that leads with the plan, is precise, and owns the call.","tips":["Open with today's plan, then the two facts that drive it.","Precise numbers, no hedging, a clear decision owned.","Residents copy what you model — make it exemplary."],"focus":["structure","impact"]},
    {"id":"together-doc-mid-08","level":"mid","profession":"doctor","title":"The M&M presentation, integrated","scenario":"Your M&M presentation must lead with the lesson, structure the case as system-not-blame, be precise about the timeline, deliver the hard truth about what failed, and land a change the room adopts. It's the full skill set in one talk.","task":"Write the opening 2-3 sentences that state the lesson, frame it as systems, and set the tone.","tips":["Lead with the teaching point, not the chronology.","Frame as system failure to keep it safe and useful.","Set up the change you'll ask the room to adopt."],"focus":["structure","impact"],"placeholder":"This case is about a critical result that sat unseen for six hours — and it's a systems story, not a blame story —"},
    {"id":"together-doc-mid-09","level":"mid","profession":"doctor","title":"The portal message that respects the reader","scenario":"A patient's portal message needs a reply that answers their real question, uses plain language, is precise about next steps, and stays warm — the whole audience-and-clarity toolkit compressed into three sentences.","task":"Write the 2-3 sentence reply integrating a direct answer, plain words, and precise next steps.","tips":["Answer the actual question first, in plain words.","Be precise about what happens next and who does it.","Warmth and precision aren't in tension — combine them."],"focus":["audience","precision"]},
    {"id":"together-doc-mid-10","level":"mid","profession":"doctor","title":"The multidisciplinary meeting you chair","scenario":"You're chairing a complex-case meeting: you must set the governing question, sequence the specialties, keep the discussion structured, and land a decision — presence, structure, and pressure-handling all at once.","task":"Write the 2-3 sentence opening that states the decision to be made and the sequence you'll follow.","tips":["Name the decision the meeting must produce, up front.","Announce the sequence so the loudest voice doesn't set it.","Chairing well is structure and presence together."],"focus":["structure","impact"],"placeholder":"We're here to decide one thing: rehab or home for Mr. Ellis. I'll take it in this order — facts first, then each service's read, then we decide —"},
    {"id":"together-doc-mid-11","level":"mid","profession":"doctor","title":"The QI proposal that survives the committee","scenario":"Your QI proposal must lead with the change, structure the evidence in pyramid form, be precise with the data, own the recommendation, and pre-empt the two objections you know are coming. The whole toolkit, one proposal.","task":"Write the opening 3-4 sentences: the change, the strongest evidence, one pre-empted objection.","tips":["Lead with the proposed change, not the problem history.","One precise data point, then the objection you'll answer.","A proposal that pre-empts objections gets voted, not deferred."],"focus":["structure","impact"]},
    {"id":"together-doc-mid-12","level":"mid","profession":"doctor","title":"The hallway CMO conversation","scenario":"The CMO catches you in the hall with a pointed question about your unit's numbers. You have thirty seconds to answer the actual question, be precise, own a recommendation, and leave them with the point — everything, standing up, no notes.","task":"Write the 3-4 sentence spoken answer: direct answer, precise reason, owned recommendation.","tips":["Answer the question asked, first and plainly.","One precise reason, then what you recommend doing.","A hallway answer is your whole toolkit in thirty seconds."],"focus":["clarity","impact"]},
    {"id":"together-doc-mid-13","level":"mid","profession":"doctor","title":"The discharge summary that serves everyone","scenario":"Your discharge summary must lead with the outcome for the family doctor, structure the follow-up clearly, be precise about medications and dates, and cut everything that doesn't change what the reader does. Multiple skills, one document.","task":"Write the opening 2-3 sentences that lead with outcome and the single most important follow-up.","tips":["Lead with diagnosis and disposition, then the key follow-up.","Precise on the one action the family doctor must take.","Cut the admission narrative to what changes their care."],"focus":["structure","audience"],"placeholder":"Discharged home after treatment for pneumonia, improving. The one thing to follow up: repeat the chest imaging in six weeks to confirm resolution —"},
    {"id":"together-doc-mid-14","level":"mid","profession":"doctor","title":"The incident debrief you lead","scenario":"You're leading a debrief after a hard event: you must structure it into fixed movements, keep it fact-first, handle the blame-seeking question, and land one owned change. Structure, pressure, and hard messages converge.","task":"Write the 2-3 sentence opening that announces the structure and sets a blame-free, fact-first tone.","tips":["Announce the movements before anyone speaks.","Set the fact-first, system-not-person frame explicitly.","The opening determines whether the debrief helps or wounds."],"focus":["structure","clarity"],"placeholder":"We'll do this in three parts: first just the timeline, then what the system let happen, then one thing we change. No blame — this is about the system —"},
    {"id":"together-doc-mid-15","level":"mid","profession":"doctor","title":"The tough feedback conversation, whole","scenario":"You're giving a resident hard feedback: you must lead with the point, use behavior-impact-ask structure, be precise with examples, stay direct under their pushback, and keep it kind. Every module in one conversation.","task":"Write the 3-4 sentence core: the specific behavior, its impact, and the ask, delivered clearly.","tips":["Ground it in one precise behavior and its real impact.","Stay direct if they push back — specifics, not defensiveness.","Clear and kind together is the whole skill."],"focus":["clarity","structure"]},
    {"id":"together-doc-mid-16","level":"mid","profession":"doctor","title":"The town hall you run","scenario":"You're running a staff town hall after a hard quarter: lead with the honest headline, structure the update, own the recommendations for next steps, answer tough questions, and close on a clear message. Presence and structure across a full hour.","task":"Write the 3-4 sentence opening that leads with the honest state of things and maps the meeting.","tips":["Open with the honest headline — the team can tell when you soften.","Map the meeting so people know it's structured, not a vent.","Set the tone that lets hard questions get asked."],"focus":["structure","impact"]},
    {"id":"together-doc-mid-17","level":"mid","profession":"doctor","title":"The referral that gets triaged fast","scenario":"A referral to a backlogged specialty must lead with the precise question and urgency, be structured, cut the noise, and give the receiving triage exactly what they need to prioritize — precision and concision together, in a referral's tight frame.","task":"Write the referral's opening 2 sentences: the precise question, the urgency, and the one deciding finding.","tips":["Lead with the question and how soon, precisely.","One deciding finding that justifies the urgency.","Cut everything triage doesn't need to prioritize."],"focus":["precision","concision"],"placeholder":"Requesting surgical assessment within two weeks: a mass that has grown measurably on repeat imaging over three weeks —"},
    {"id":"together-doc-mid-18","level":"mid","profession":"doctor","title":"The budget pitch that lands","scenario":"You're pitching for equipment to the finance committee: lead with the ask, translate clinical value into financial terms, be precise with numbers, own the recommendation, and pre-empt the delay objection. The full persuasive toolkit for a skeptical audience.","task":"Write the opening 3-4 sentences: the ask, the value in financial terms, the pre-empted objection.","tips":["Lead with the ask and its cost-benefit in their language.","Precise numbers, translated into what finance manages.","Answer 'why not wait' before they raise it."],"focus":["audience","impact"]},
    {"id":"together-doc-mid-19","level":"mid","profession":"doctor","title":"The disclosure conversation, integrated","scenario":"An error-disclosure conversation demands everything: lead with what happened clearly, be precise about the facts, deliver the hard truth without minimizing, stay steady under the family's distress, and be genuinely compassionate. The hardest integration.","task":"Write the opening 3-4 sentences that disclose clearly, precisely, and compassionately.","tips":["Lead with what happened, plainly and without minimizing.","Precise facts, then genuine ownership.","Steady and compassionate under distress is the whole skill."],"focus":["clarity","audience"],"placeholder":"I need to tell you about a mistake in your father's care, and I want to be completely clear about it. Yesterday he received the wrong dose of a medication —"},
    {"id":"together-doc-mid-20","level":"mid","profession":"doctor","title":"The handoff that leaves nothing to chance","scenario":"Your end-of-service handoff to a covering physician must lead with the sickest patient, structure by acuity, be precise about contingencies, cut the noise, and be usable by someone with no local knowledge. Every skill, one high-stakes document.","task":"Write the handoff's opening: the sickest patient, the precise if-then contingency, in a form a stranger could act on.","tips":["Lead with the one patient the covering doctor must watch.","Precise if-then: if X, do Y, call Z at this number.","Write it so someone new to the building can act at 2am."],"focus":["structure","precision"],"placeholder":"Watch bed 8 first: 74, day two post-op, new confusion this afternoon, head CT pending. If she desaturates below 90, call Dr. Okafor directly at ext. 4471 — don't wait —"},
    {"id":"together-doc-mid-21","level":"mid","profession":"doctor","title":"The grand rounds talk, fully built","scenario":"Your grand rounds talk needs a governing idea, three supporting sections, precise evidence, an owned conclusion, and a narrative spine that carries a senior audience. This is the long-form integration of everything.","task":"Write the talk's opening 3-4 sentences: the governing idea, the map of three sections, the hook.","tips":["State the governing idea a listener could repeat afterward.","Map the three sections so they can follow the argument.","Open with a hook that earns the next forty minutes."],"focus":["structure","impact"]},
    {"id":"together-doc-mid-22","level":"mid","profession":"doctor","title":"The negotiation with a peer service","scenario":"You're negotiating shared coverage with another service's lead: you must state your ask clearly, be precise about the constraints, own a proposal, stay composed under their pushback, and frame it around mutual benefit. Persuasion and pressure together.","task":"Write the 3-4 sentence opening: your clear ask, the constraint, and the mutual-benefit frame.","tips":["Lead with the specific ask and what you're offering.","Precise about the constraint driving it.","Frame around what they gain, not just what you need."],"focus":["clarity","audience"]},
    {"id":"together-doc-mid-23","level":"mid","profession":"doctor","title":"The annual service review, complete","scenario":"You present your service's annual review to the department: a governing story, structured sections, precise metrics, an owned assessment of the year, and next year's ask — the whole year and the whole toolkit in ten minutes.","task":"Write the opening 3-4 sentences: the year's governing story and the map of what you'll cover.","tips":["Find the year's one-sentence story and lead with it.","Map the sections so ten minutes feels structured.","End the opening pointing at next year's ask."],"focus":["structure","impact"],"placeholder":"The story of this year: we grew 20% and held our quality numbers, but the seams are showing — and that shapes what I'll ask for —"},
    {"id":"together-doc-mid-24","level":"mid","profession":"doctor","title":"The crisis communication to the unit","scenario":"An unexpected crisis hits your unit mid-shift — a systems outage affecting patient care. You must communicate to the team fast: lead with what to do now, structure the response, be precise, stay calm, and project the presence that steadies everyone.","task":"Write the 2-3 sentence message that leads with the immediate action and projects calm command.","tips":["Lead with what everyone does right now, precisely.","Structure the rest, but the action comes first.","Calm, specific, and decisive is what steadies a unit."],"focus":["clarity","impact"],"placeholder":"Here's what we do right now: switch to paper charting using the packets in each station, and I'll coordinate with IT. Stay calm — we've drilled this —"},
    {"id":"together-doc-mid-25","level":"mid","profession":"doctor","title":"The capstone: your case for the year's biggest change","scenario":"You're making the case to the executive committee for the biggest change your service needs this year — a new role, a restructure, a major investment. You have ten minutes and everything you've learned: lead, audience, structure, precision, presence, pressure, narrative, and clarity, all at once.","task":"Write the opening 4-5 sentences that lead with the ask, frame the stakes, and set up the case.","tips":["Lead with the ask, then the stakes that make it urgent.","Structure the case so the committee can follow and vote.","This is every skill converging — make each sentence earn its place."],"focus":["structure","impact"],"placeholder":"I'm asking the committee to approve a dedicated discharge team for the unit this year. Here's why it's the highest-leverage change we can make — and what it costs us to keep waiting —"}
  ]
};
